import { createClient } from '@supabase/supabase-js';
import dotenv from 'dotenv';
dotenv.config({ path: '.env.local' });

const supabase = createClient(process.env.NEXT_PUBLIC_SUPABASE_URL, process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY);

async function checkSchema() {
    const tables = ['profiles', 'mentees', 'mentor_requests'];
    
    for (const table of tables) {
        console.log(`\n--- Checking table: ${table} ---`);
        const { data, error } = await supabase.from(table).select('*').limit(1);
        
        if (error) {
            console.error(`Error fetching ${table}:`, error.message, error.code);
        } else if (data && data.length > 0) {
            console.log(`Columns in ${table}:`, Object.keys(data[0]));
        } else {
            console.log(`Table ${table} is empty or has no data, but no error returned.`);
            // Try to get one row with just ID to see if it even exists
            const { data: d2, error: e2 } = await supabase.from(table).select('id').limit(1);
            if (e2) {
                console.error(`Error checking existence of ${table}:`, e2.message);
            } else {
                console.log(`Table ${table} exists.`);
            }
        }
    }
}

checkSchema();

import { createClient } from '@supabase/supabase-js';
import fs from 'fs';
import path from 'path';

// Manual env parsing to avoid dotenv dependency issues
const envFile = fs.readFileSync('.env.local', 'utf8');
const env = {};
envFile.split('\n').forEach(line => {
    const [key, ...value] = line.split('=');
    if (key && value) env[key.trim()] = value.join('=').trim();
});

const supabase = createClient(env.NEXT_PUBLIC_SUPABASE_URL, env.NEXT_PUBLIC_SUPABASE_ANON_KEY);


async function debugFetch() {
    console.log("--- Starting Debug Fetch ---");
    const results = {
        mentees: null,
        requests: null,
        assignments: null
    };

    try {
        // 1. Test Mentees Query
        const { data: mData, error: mError } = await supabase
            .from('mentees')
            .select(`
                id,
                profiles:profiles!id(id, full_name, email, student_id)
            `)
            .limit(1);
        results.mentees = mError ? { error: mError } : { success: true, count: mData?.length };

        // 2. Test Mentor Requests Query
        const { data: rData, error: rError } = await supabase
            .from('mentor_requests')
            .select('*, mentee:profiles!mentee_id(full_name, student_id)')
            .limit(1);
        results.requests = rError ? { error: rError } : { success: true, count: rData?.length };

        // 3. Test Assignments Query
        const { data: aData, error: aError } = await supabase
            .from('assignments')
            .select('mentee_id, status')
            .limit(1);
        results.assignments = aError ? { error: aError } : { success: true, count: aData?.length };

    } catch (e) {
        results.fatal = e.message;
    }

    fs.writeFileSync('debug_results.json', JSON.stringify(results, null, 2));
    console.log("Results saved to debug_results.json");
}

debugFetch();

