                                    <div className="space-y-2">
                                        <label className="text-xs font-black text-slate-500 dark:text-slate-400 uppercase tracking-widest ml-1">Announcement Message</label>
                                        <textarea
                                            required
                                            rows={5}
                                            value={form.content}
                                            onChange={e => setForm(p => ({ ...p, content: e.target.value }))}
                                            placeholder="Type your message here..."
                                            className="w-full px-5 py-4 rounded-2xl bg-slate-50 dark:bg-white/5 border border-slate-200 dark:border-white/5 outline-none focus:border-primary focus:ring-4 focus:ring-primary/10 transition-all font-medium text-sm resize-none"
                                        />
                                    </div>
                                    <div className="flex gap-4 pt-4">
                                        <button
                                            type="button"
                                            onClick={() => { setIsComposing(false); setForm({ title: "", content: "" }); }}
                                            className="flex-1 px-6 py-4 rounded-2xl border border-slate-200 dark:border-white/10 text-slate-600 dark:text-slate-400 font-black text-sm hover:bg-slate-50 dark:hover:bg-white/5 transition-all active:scale-95"
                                        >
                                            Cancel
                                        </button>
                                        <button
                                            type="submit"
                                            disabled={isPosting}
                                            className="flex-1 px-6 py-4 rounded-2xl bg-primary text-white font-black text-sm hover:bg-blue-700 shadow-xl shadow-primary/20 transition-all disabled:opacity-50 disabled:active:scale-100 active:scale-95 flex items-center justify-center gap-2"
                                        >
                                            {isPosting ? (
                                                <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                                            ) : (
                                                <>
                                                    <Send className="w-4 h-4" />
                                                    Post to Group
                                                </>
                                            )}
                                        </button>
                                    </div>
                                </form>
                            </motion.div>
                        </motion.div>
                    )}
                </AnimatePresence>

                {/* Main Content Area */}
                {loading ? (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        {[1, 2, 3, 4].map(i => (
                            <div key={i} className="h-44 rounded-2xl shimmer-skeleton bg-white/40 dark:bg-slate-900/40 border border-slate-200/50 dark:border-white/5" />
                        ))}
