function AnnouncementCard({
    announcement,
    isMentor,
    isRead,
    menteeCount,
    onMarkRead,
    onDelete,
    index
}: {
    announcement: any;
    isMentor: boolean;
    isRead: boolean;
    menteeCount?: number;
    onMarkRead?: () => void;
    onDelete?: () => void;
    index: number;
}) {
    const readCount = announcement.reads?.[0]?.count ?? 0;

    return (
        <motion.div
            initial={{ opacity: 0, scale: 0.98, y: 12 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.98, y: -12 }}
            transition={{ 
                duration: 0.4, 
                delay: index * 0.05,
                ease: [0.23, 1, 0.32, 1] 
            }}
            whileHover={{ y: -2 }}
            className={`group relative glass p-4 sm:p-5 rounded-2xl border transition-all duration-300 ${
                !isRead && !isMentor
                    ? "border-primary/40 bg-gradient-to-br from-primary/10 to-blue-500/5 dark:from-primary/20 dark:to-blue-600/10 shadow-xl shadow-primary/5"
                    : "border-white/40 dark:border-slate-800/50 hover:border-primary/20 shadow-sm"
            }`}
        >
            {/* New Badge Glow */}
            {!isRead && !isMentor && (
                <div className="absolute -top-1 -left-1 w-3 h-3 bg-primary rounded-full blur-[4px] animate-pulse" />
            )}

            <div className="flex items-start gap-5">
                {/* Icon Column */}
                <div className="flex flex-col items-center gap-2">
                    <div className={`w-10 h-10 rounded-xl flex items-center justify-center shrink-0 shadow-inner ${
                        !isRead && !isMentor 
                            ? "bg-gradient-to-br from-primary to-blue-600 text-white shadow-primary/20" 
                            : "bg-slate-100 dark:bg-slate-800/50 text-slate-400 group-hover:text-primary transition-colors"
                    }`}>
                        <Megaphone className="w-5 h-5" />
                    </div>
                </div>

                <div className="flex-1 min-w-0">
                    <div className="flex items-start justify-between gap-3">
                        <div className="space-y-1">
                            <h3 className="text-lg font-black text-slate-900 dark:text-white leading-tight tracking-tight group-hover:text-primary transition-colors">
                                {announcement.title}
                            </h3>
                            <div className="flex items-center gap-2">
                                <span className="flex items-center gap-1.5 text-[10px] font-bold text-slate-400 uppercase tracking-widest">
                                    <Clock className="w-3 h-3" /> {timeAgo(announcement.created_at)}
                                </span>
                                {!isRead && !isMentor && (
                                    <span className="bg-primary text-white text-[9px] font-black px-2 py-0.5 rounded-full uppercase tracking-widest animate-in zoom-in duration-300">
                                        New
                                    </span>
                                )}
                            </div>
                        </div>

                        {isMentor && (
                            <button
                                onClick={onDelete}
                                className="p-2 text-slate-300 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-950/30 rounded-2xl transition-all opacity-0 group-hover:opacity-100 scale-90 group-hover:scale-100"
                            >
                                <Trash2 className="w-4.5 h-4.5" />
                            </button>
                        )}
                    </div>

                    <p className="text-[15px] text-slate-600 dark:text-slate-300 mt-4 leading-relaxed font-medium">
                        {announcement.content}
                    </p>

                    <div className="mt-6 flex flex-wrap items-center justify-between gap-4 border-t border-slate-100 dark:border-white/5 pt-4">
                        {/* Mentor Stats / Mentee Read Status */}
                        {isMentor ? (
                            <div className="flex items-center gap-2 px-3 py-1.5 bg-slate-50 dark:bg-white/5 rounded-xl border border-slate-100 dark:border-white/5 transition-all group-hover:border-primary/10">
                                <Users className="w-3.5 h-3.5 text-primary" />
                                <span className="text-[11px] font-black text-slate-500 dark:text-slate-400 uppercase tracking-wide">
                                    Read by <span className="text-primary">{readCount}</span> / {menteeCount} Mentees
                                </span>
                            </div>
                        ) : (
                            <div className="flex items-center gap-2">
                                {!isRead ? (
                                    <button
                                        onClick={onMarkRead}
                                        className="flex items-center gap-2 px-4 py-2 bg-primary/10 hover:bg-primary text-primary hover:text-white text-xs font-black rounded-xl transition-all active:scale-95 group/btn"
                                    >
                                        <CheckCircle2 className="w-4 h-4 group-hover/btn:scale-110 transition-transform" />
                                        Got it ΓÇö Mark as Read
                                    </button>
                                ) : (
                                    <span className="flex items-center gap-2 px-3 py-1.5 bg-emerald-500/5 text-emerald-500 text-[10px] font-black uppercase tracking-widest rounded-xl border border-emerald-500/10">
                                        <CheckCircle2 className="w-3.5 h-3.5" />
                                        Read & Acknowledged
                                    </span>
                                )}
                            </div>
                        )}

                        {/* Visual Ornament */}
                        <div className="hidden sm:flex items-center gap-1 opacity-20 group-hover:opacity-40 transition-opacity">
                            {[1, 2, 3].map(i => (
                                <div key={i} className="w-1 h-1 rounded-full bg-primary" />
                            ))}
                        </div>
                    </div>
                </div>
            </div>
        </motion.div>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import { motion } from "framer-motion";
import {
    Users,
    Calendar,
    CheckCircle2,
    Clock,
    ChevronRight,
    Megaphone,
    X
} from "lucide-react";
import { getInitials, formatDate } from "@/lib/date-utils";
import Link from "next/link";
import { supabase } from "@/lib/supabase";
import { useRouter } from "next/navigation";
import { logger } from "@/lib/logger";

import { 
    DashboardSession, 
    DashboardMentee, 
    DashboardActivity 
} from "../page";

interface MenteeProgress {
    mentorName: string;
    nextSession: string;
    taskProgress: number;
    total_sessions_attended: number;
    mentor_id: string | null;
}

interface MenteeDashboardProps {
    profile: any;
    user: any;
    pendingRequests: any[];
    menteeProgress: MenteeProgress;
    dataLoading: boolean;
    handleAcceptRequest: (request: any) => Promise<void>;
    handleRejectRequest: () => Promise<void>;
    setShowRejectionModal: (show: boolean) => void;
    setSelectedRequest: (request: any) => void;
    rejectionReason: string;
    setRejectionReason: (reason: string) => void;
    showRejectionModal: boolean;
    selectedRequest: any;
    isProcessingRequest: boolean;
    toast: (msg: string, type?: "success" | "error" | "info" | "warning") => void;
}

export function MenteeDashboard({
    profile,
    user,
    pendingRequests,
    menteeProgress,
    dataLoading,
    handleAcceptRequest,
    handleRejectRequest,
    setShowRejectionModal,
    setSelectedRequest,
    rejectionReason,
    setRejectionReason,
    showRejectionModal,
    selectedRequest,
    isProcessingRequest,
    toast
}: MenteeDashboardProps) {
    const router = useRouter();
    const [unreadAnnouncement, setUnreadAnnouncement] = useState<any>(null);
    const [bannerDismissed, setBannerDismissed] = useState(false);

    useEffect(() => {
        if (!user?.id) return;
        const fetch = async () => {
            try {
                const { data: menteeRow } = await supabase
                    .from("mentees")
                    .select("assigned_mentor_id")
                    .eq("id", user.id)
                    .maybeSingle();
                if (!menteeRow?.assigned_mentor_id) return;

                const { data: readData } = await supabase
                    .from("announcement_reads")
                    .select("announcement_id")
                    .eq("mentee_id", user.id);
                const readIds = new Set((readData || []).map((r: any) => r.announcement_id));

                const { data: announcements } = await supabase
                    .from("announcements")
                    .select("id, title, content")
                    .eq("mentor_id", menteeRow.assigned_mentor_id)
                    .order("created_at", { ascending: false });

                const unread = (announcements || []).find((a: any) => !readIds.has(a.id));
                if (unread) setUnreadAnnouncement(unread);
            } catch (error) {
                logger.warn("MenteeDashboard", "Failed to fetch announcements", error);
            }
        };
        fetch();
    }, [user?.id]);

    return (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
                <div>
                    <h1 className="text-2xl sm:text-3xl font-black text-slate-900 dark:text-white mb-1 tracking-tight">Academic Dashboard</h1>
                    <p className="text-sm sm:text-base text-slate-500 dark:text-slate-400 font-medium">
                        Welcome back, <span className="text-primary font-bold">
                            {(() => {
                                const name = profile?.full_name || user?.user_metadata?.full_name || 'Mentee';
                                const parts = name.split(' ');
                                const titles = ['dr', 'dr.', 'prof', 'prof.', 'mr', 'mr.', 'ms', 'ms.', 'mrs', 'mrs.'];
                                if (parts.length > 1 && titles.includes(parts[0].toLowerCase())) {
                                    return `${parts[0]} ${parts[1]}`;
                                }
                                return parts[0];
                            })()}
                        </span>.
                    </p>
                </div>
                <div className="w-fit px-4 py-1.5 bg-emerald-500/10 text-emerald-600 dark:text-emerald-400 rounded-full text-[10px] font-black uppercase tracking-[0.2em] border border-emerald-500/20">Mentee Account</div>
            </div>

            {/* Pending Request Notification(s) */}
            {pendingRequests.length > 0 && (
                <div className="space-y-4">
                    {pendingRequests.map((request) => (
                        <motion.div
                            key={request.id}
                            initial={{ opacity: 0, scale: 0.95 }}
                            animate={{ opacity: 1, scale: 1 }}
                            className="p-5 rounded-2xl bg-gradient-to-r from-blue-600 to-indigo-700 text-white shadow-xl shadow-blue-500/10 relative overflow-hidden"
                        >
                            <div className="relative z-10 flex flex-col md:flex-row md:items-center justify-between gap-6">
                                <div className="space-y-2">
                                    <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-white/20 text-[10px] font-black uppercase tracking-widest border border-white/10">Action Required</div>
                                    <h2 className="text-xl font-bold">Mentor Connection Request</h2>
                                    <p className="text-white/80 text-sm max-w-xl">
                                        <strong className="text-white font-bold">{request.mentor?.full_name}</strong> wants to guide you as your official mentor.
                                        {request.mentor?.expertise && ` They specialize in ${request.mentor.expertise.join(', ')}.`}
                                    </p>
                                </div>
                                <div className="flex items-center gap-3 shrink-0">
                                    <button
                                        onClick={() => handleAcceptRequest(request)}
                                        disabled={isProcessingRequest}
                                        className="px-6 py-3 rounded-xl bg-white text-blue-600 font-bold hover:bg-slate-50 active:scale-95 transition-all shadow-lg shadow-white/20 disabled:opacity-50"
                                    >
                                        {isProcessingRequest && selectedRequest?.id === request.id ? "Accepting..." : "Accept Connection"}
                                    </button>
                                    <button
                                        onClick={() => { setSelectedRequest(request); setShowRejectionModal(true); }}
                                        disabled={isProcessingRequest}
                                        className="px-6 py-3 rounded-xl bg-white/10 text-white font-bold hover:bg-white/20 transition-colors border border-white/20 active:scale-95 disabled:opacity-50"
                                    >
                                        Decline
                                    </button>
                                </div>
                            </div>
                        </motion.div>
                    ))}
                </div>
            )}

            {/* Announcement Banner */}
            {unreadAnnouncement && !bannerDismissed && (
                <motion.div
                    initial={{ opacity: 0, y: -8 }}
                    animate={{ opacity: 1, y: 0 }}
                    className="flex items-start gap-3 p-4 bg-primary/10 border border-primary/20 rounded-2xl cursor-pointer group"
                    onClick={() => router.push("/dashboard/announcements")}
                >
                    <div className="w-8 h-8 rounded-xl bg-primary/20 flex items-center justify-center shrink-0 group-hover:bg-primary/30 transition-colors">
                        <Megaphone className="w-4 h-4 text-primary" />
                    </div>
                    <div className="flex-1 min-w-0">
                        <p className="text-xs font-black text-primary uppercase tracking-widest">≡ƒôó New Announcement</p>
                        <p className="text-sm font-semibold text-slate-800 dark:text-white truncate mt-0.5">{unreadAnnouncement.title}</p>
                        <p className="text-xs text-slate-500 line-clamp-1 mt-0.5">{unreadAnnouncement.content}</p>
                    </div>
                    <button
                        onClick={e => { e.stopPropagation(); setBannerDismissed(true); }}
                        className="p-1 text-slate-400 hover:text-slate-600 shrink-0"
                    >
                        <X className="w-3.5 h-3.5" />
                    </button>
                </motion.div>
