                        statConfig.key === 'completionRate' ? `${value}%` :
                            value.toString();

                    return (
                        <motion.div
                            key={i}
                            initial={{ opacity: 0, y: 10 }}
                            animate={{ opacity: 1, y: 0 }}
                            transition={{ delay: i * 0.1 }}
                            className="glass p-4 sm:p-5 rounded-2xl border border-slate-200/50 dark:border-white/5 hover:border-primary/20 transition-all group shadow-sm hover:shadow-md"
                        >
                            <div
                                className="relative z-10 cursor-pointer"
                                onClick={() => {
                                    if (statConfig.key === 'totalSessions' || statConfig.key === 'hoursGuided') router.push('/dashboard/sessions');
                                    else if (statConfig.key === 'activeMentees') router.push('/dashboard/mentees');
                                    else router.push('/dashboard/tasks');
                                }}
                            >
                                <div className={`w-9 h-9 sm:w-11 sm:h-11 ${statConfig.bg} ${statConfig.color} rounded-xl flex items-center justify-center mb-3 sm:mb-4 shadow-inner group-hover:scale-105 transition-transform`}>
                                    <statConfig.icon className="w-4.5 h-4.5 sm:w-5.5 h-5.5" />
                                </div>
                                {dataLoading && value === 0 ? (
                                    <div className="h-8 w-16 bg-slate-200 dark:bg-slate-800 rounded-xl shimmer-skeleton mb-2" />
                                ) : (
                                    <div className="text-xl xs:text-2xl sm:text-3xl font-black text-slate-900 dark:text-white tracking-tight leading-none mb-1 sm:mb-1.5">{displayValue}</div>
