                                    <div key={session.id} className="p-4 rounded-2xl bg-white/60 dark:bg-slate-900/40 backdrop-blur-md border border-slate-200/50 dark:border-white/5 flex flex-col sm:flex-row sm:items-center justify-between group hover:shadow-xl transition-all gap-4 overflow-hidden relative">
                                        <div className="absolute inset-y-0 left-0 w-1 bg-primary transform -translate-x-full group-hover:translate-x-0 transition-transform" />
                                        <div className="flex items-center gap-4 relative z-10">
                                            <div className="w-12 h-12 rounded-2xl bg-primary/10 flex items-center justify-center text-primary font-black text-xl shadow-inner group-hover:scale-105 transition-transform shrink-0">
