                                                <div className="flex items-center gap-2 mt-0.5">
                                                    <span className="w-1.5 h-1.5 rounded-full bg-emerald-500" />
                                                    <p className="text-xs text-slate-500 font-bold uppercase tracking-widest truncate">{session.title || 'Session'} &middot; {session.scheduled_at ? formatDate(session.scheduled_at) : ''}</p>
                                                </div>
                                            </div>
                                        </div>
                                        <div className="flex items-center justify-between sm:justify-start gap-4 border-t sm:border-t-0 border-slate-100 dark:border-slate-800/50 pt-3 sm:pt-0">
                                            <span className="px-3 py-1.5 rounded-full bg-primary/10 text-primary text-[10px] font-black tracking-widest uppercase">Upcoming</span>
                                            <button
                                                onClick={(e) => {
                                                    e.stopPropagation();
                                                    if (session.meeting_link) window.open(session.meeting_link, '_blank');
                                                    else router.push('/dashboard/sessions');
                                                }}
                                                className="flex items-center gap-2 px-4 py-2 sm:p-2 rounded-xl bg-primary/5 sm:bg-transparent text-primary sm:text-slate-400 hover:bg-primary/10 transition-colors group/btn"
