                                                <span className="sm:hidden text-xs font-bold">Join Call</span>
                                                <ArrowUpRight className="w-5 h-5 group-hover/btn:text-primary transition-colors" />
                                            </button>
                                        </div>
                                    </div>
                                ))}
                            </div>
