                            <div className="p-8 rounded-2xl bg-slate-50 dark:bg-slate-900/50 border border-slate-100 dark:border-slate-800/50 text-center">
                                <p className="text-slate-500 dark:text-slate-400">No upcoming sessions scheduled</p>
                            </div>
                        )}
                    </div>

                    <div className="space-y-6">
                        <div className="flex items-center justify-between">
                            <h2 className="text-xl font-bold text-slate-900 dark:text-white">Active Mentees ({stats.activeMentees})</h2>
                            <button onClick={() => router.push('/dashboard/mentees')} className="text-sm font-bold text-primary hover:underline flex items-center gap-1">
                                Full Directory <ArrowUpRight className="w-4 h-4" />
                            </button>
                        </div>
                        {activeMentees.length > 0 ? (
                            <div className="grid grid-cols-1 lg:grid-cols-2 xl:grid-cols-3 gap-4">
                                {activeMentees.slice(0, 6).map((mentee) => (
                                    <Link
                                        key={mentee.id}
                                        href={`/dashboard/mentees/detail?id=${mentee.id}`}
                                        className="p-4 rounded-2xl bg-white/40 dark:bg-slate-800/40 backdrop-blur-sm border border-slate-200/30 dark:border-slate-700/50 flex flex-col justify-center hover:bg-white/60 dark:hover:bg-slate-800/60 transition-all hover:shadow-lg group cursor-pointer gap-2.5 block"
                                    >
                                        <div className="flex items-center gap-3">
                                            <div className="w-10 h-10 rounded-xl bg-primary/10 flex items-center justify-center text-primary font-bold text-sm group-hover:scale-110 transition-transform">
                                                {mentee.initials || getInitials(mentee.name)}
                                            </div>
                                            <div className="font-bold text-slate-900 dark:text-white text-sm truncate">{mentee.name}</div>
                                        </div>
                                        <div className="w-full bg-slate-200 dark:bg-slate-900/50 h-1.5 rounded-full overflow-hidden shadow-inner">
                                            <div className="bg-gradient-to-r from-primary to-blue-500 h-full rounded-full transition-all duration-1000 ease-out" style={{ width: `${mentee.progress}%` }} />
                                        </div>
                                    </Link>
