                                {activeMentees.length > 6 && (
                                    <div
                                        onClick={() => router.push('/dashboard/mentees')}
                                        className="p-5 rounded-2xl bg-primary/5 dark:bg-primary/10 backdrop-blur-sm border border-primary/20 flex items-center justify-center hover:bg-primary/10 transition-all group cursor-pointer border-dashed"
                                    >
                                        <div className="text-center">
                                            <div className="text-primary font-black text-lg">+{activeMentees.length - 6}</div>
                                            <div className="text-[10px] font-black text-primary/60 uppercase tracking-widest">More Mentees</div>
                                        </div>
                                    </div>
                                )}
                            </div>
                        ) : (
                            <div className="p-8 rounded-2xl bg-slate-50/50 dark:bg-slate-900/50 border border-slate-100 dark:border-slate-800/50 text-center">
                                <p className="text-slate-500 dark:text-slate-400 font-medium">No mentees assigned yet</p>
                            </div>
                        )}
                    </div>
                </div>

                {/* Quick Actions / Recent Activity */}
                <div className="space-y-6">
                    <h2 className="text-xl font-bold text-slate-900 dark:text-white">Recent Activity</h2>
                    <div className="p-5 rounded-2xl bg-gradient-to-br from-slate-900 to-slate-800 dark:from-slate-900 dark:to-slate-800/80 border border-slate-700 shadow-xl shadow-slate-900/20 text-white space-y-4 relative overflow-hidden">
                        <div className="relative z-10 space-y-4">
                            {recentActivity.length > 0 ? recentActivity.map((activity) => (
                                <React.Fragment key={activity.id}>
                                    <div className="flex items-start gap-4 p-3 rounded-xl hover:bg-white/5 transition-colors">
                                        <div className={`w-2 h-2 mt-2 rounded-full ${activity.type === 'task' ? 'bg-blue-400 shadow-[0_0_8px_rgba(96,165,250,0.8)]' : 'bg-purple-400 shadow-[0_0_8px_rgba(192,132,252,0.8)]'}`} />
                                        <p className="text-slate-300 text-sm leading-relaxed">
                                            {activity.text} <strong className="text-white font-semibold">{activity.bold}</strong>.
                                        </p>
                                    </div>
                                    <div className="h-[1px] bg-slate-700/50 w-full last:hidden" />
                                </React.Fragment>
                            )) : (
                                <p className="text-slate-400 text-sm italic text-center py-4">No recent activity found.</p>
                            )}
                        </div>
                    </div>

                    <button
                        onClick={() => router.push('/dashboard/sessions')}
                        className="w-full py-4 rounded-2xl bg-gradient-to-r from-primary to-blue-600 shrink-0 text-white font-bold hover:shadow-[0_0_20px_rgba(37,99,235,0.4)] hover:-translate-y-0.5 transition-all duration-300">
                        Schedule New Session
                    </button>
                </div>
            </div>
        </div>
    );
}

/**
 * @file dashboard/layout.tsx
 * @description Shared layout wrapper for all authenticated dashboard pages.
 *
 * Renders the desktop Sidebar, top navigation Header, and mobile bottom nav.
 * Guards rendering behind `ProtectedRoute` to block unauthenticated access.
 *
 * DESIGN DECISION: This layout renders the shell IMMEDIATELY, even while auth
 * is still resolving. Pages handle their own data-loading skeletons.
 * We never show a full-screen blocking spinner here to keep perceived
 * performance fast on every navigation.
 */

"use client";

import React, { useState, useRef, useEffect } from "react";
import { Sidebar } from "@/components/Sidebar";
import { MobileNav } from "@/components/MobileNav";
import { ProtectedRoute } from "@/components/ProtectedRoute";
import { CONFIG } from "@/lib/config";
import { useAuth } from "@/contexts/AuthContext";
import { getInitials, formatDate, timeAgo } from "@/lib/date-utils";
import { Bell, LogOut, Check, X, MessageSquare, Calendar, UserPlus, Trash2, WifiOff, CheckSquare, Megaphone } from "lucide-react";
import { supabase } from "@/lib/supabase";
import { useRouter, usePathname } from "next/navigation";
import { useToast } from "@/components/Toast";
import { cn } from "@/lib/utils";
import { motion, AnimatePresence } from "framer-motion";

export default function DashboardLayout({
    children,
}: {
    children: React.ReactNode;
}) {
    const { profile, displayName, loading, globalData, markNotificationRead, signOut } = useAuth();
    const router = useRouter();
    const pathname = usePathname();
    const isMessagesPage = pathname === "/dashboard/messages";
    const { confirm, toast } = useToast();

    const [isNotifOpen, setIsNotifOpen] = useState(false);
    const [mounted, setMounted] = useState(false);
    const [isOffline, setIsOffline] = useState(false);

    useEffect(() => {
        setMounted(true);
        const handleOnline = () => setIsOffline(false);
        const handleOffline = () => setIsOffline(true);

        window.addEventListener('online', handleOnline);
        window.addEventListener('offline', handleOffline);
        setIsOffline(!navigator.onLine);

        return () => {
            window.removeEventListener('online', handleOnline);
            window.removeEventListener('offline', handleOffline);
        };
    }, []);
    const notifications = globalData.notifications || [];
    const unreadCount = notifications.filter(n => !n.is_read).length;
    const notifRef = useRef<HTMLDivElement>(null);

    // Close notifications on click outside
    useEffect(() => {
        function handleClickOutside(event: MouseEvent) {
            if (notifRef.current && !notifRef.current.contains(event.target as Node)) {
                setIsNotifOpen(false);
            }
        }
        document.addEventListener("mousedown", handleClickOutside);
        return () => document.removeEventListener("mousedown", handleClickOutside);
    }, []);

    const handleMarkAllRead = async () => {
        const unreadIds = notifications.filter(n => !n.is_read).map(n => n.id);
        for (const id of unreadIds) {
            await markNotificationRead(id);
        }
        toast("All marked as read", "success");
    };

    const [isLogoutLoading, setIsLogoutLoading] = useState(false);

    const handleLogout = async () => {
        const ok = await confirm({
            title: "Log Out",
            message: "Are you sure you want to log out of NEXUS? You will need to sign in again to access your dashboard.",
            confirmText: "Log Out",
            cancelText: "Stay",
            variant: "danger"
        });
        if (!ok) return;

        setIsLogoutLoading(true);
        try {
            await signOut();
        } catch (error) {
            window.location.replace("/");
        }
    };

    // Use the centralized, sanitized display name from AuthContext
    const userName = displayName;
    const initials = getInitials(profile?.full_name || displayName);


    // Determine greeting based on current hour - STABILIZED FOR HYDRATION
    const [greeting, setGreeting] = useState("Day"); // Initial fixed value for SSR
    useEffect(() => {
        if (!mounted) return;
        const hour = new Date().getHours();
        setGreeting(hour < 12 ? "Morning" : hour < 18 ? "Afternoon" : "Evening");
    }, [mounted]);

    return (
        <div className="flex bg-slate-50 dark:bg-slate-950 h-[100dvh] overflow-hidden">
            {/* Desktop Sidebar */}
            <div className="hidden md:flex h-full">
                <Sidebar />
            </div>

            {/* Main content column */}
            <div className="flex-1 flex flex-col h-full overflow-hidden relative">

                {/* Offline Warning Banner */}
                <AnimatePresence>
                    {isOffline && (
                        <motion.div 
                            initial={{ height: 0, opacity: 0 }}
                            animate={{ height: 'auto', opacity: 1 }}
                            exit={{ height: 0, opacity: 0 }}
                            className="bg-red-500 text-white text-xs sm:text-sm font-bold flex items-center justify-center gap-2 py-2 px-4 shadow-md z-40"
                        >
                            <WifiOff className="w-4 h-4 shrink-0 animate-pulse" />
                            <span>You are currently offline. Real-time updates are paused.</span>
                        </motion.div>
                    )}
                </AnimatePresence>

                {/* Top Header */}
                <header className={cn(
                    "h-16 sm:h-20 glass shrink-0 flex items-center justify-between px-4 sm:px-10 z-30 border-b border-white/20 dark:border-slate-800/50",
                    isMessagesPage && "hidden md:flex"
                )}>
                    <div className="flex items-center gap-1.5 overflow-hidden mr-4">
                        {/* NEXUS logo pill ΓÇö visible on mobile only */}
                        <span className="md:hidden w-8 h-8 bg-primary rounded-lg flex items-center justify-center text-white text-xs font-black shrink-0">
                            {CONFIG.platform.logoText}
                        </span>
                        <h2 className="text-xl font-black text-slate-900 dark:text-white tracking-tight flex items-center gap-1.5 truncate">
                            <span className="opacity-60 font-semibold truncate max-w-[40px] min-[400px]:max-w-none text-sm min-[400px]:text-base">Hi,</span>
                            <span className="text-primary truncate max-w-[70px] min-[400px]:max-w-[120px] sm:max-w-[240px] capitalize text-sm min-[400px]:text-base">
                                {!mounted || !profile ? '...' : (() => {
                                    const name = profile.full_name || displayName;
                                    const parts = name.split(' ');
                                    const titles = ['dr', 'dr.', 'prof', 'prof.', 'mr', 'mr.', 'ms', 'ms.', 'mrs', 'mrs.'];
                                    if (parts.length > 1 && titles.includes(parts[0].toLowerCase())) {
                                        return `${parts[0]} ${parts[1]}`;
                                    }
                                    return parts[0];
                                })()}
                            </span>
                        </h2>
                    </div>

                    {/* Header Actions */}
                    <div className="flex items-center gap-1.5 sm:gap-4">
                        <div className="flex items-center relative" ref={notifRef}>
                            <button
                                onClick={() => setIsNotifOpen(!isNotifOpen)}
                                className={cn(
                                    "relative p-2.5 rounded-xl transition-all text-xs border",
                                    isNotifOpen
                                        ? "text-primary bg-primary/10 border-primary/20"
                                        : "text-slate-400 hover:text-primary hover:bg-primary/5 border-transparent hover:border-primary/10"
                                )}
                            >
                                <Bell className="w-5 h-5" />
                                {mounted && unreadCount > 0 && (
                                    <span className="absolute top-2.5 right-2.5 w-2.5 h-2.5 bg-rose-500 rounded-full border-2 border-white dark:border-slate-900" />
                                )}
                            </button>

                            <AnimatePresence>
                                {isNotifOpen && (
                                    <motion.div
                                        initial={{ opacity: 0, y: 10, scale: 0.95 }}
                                        animate={{ opacity: 1, y: 0, scale: 1 }}
                                        exit={{ opacity: 0, y: 10, scale: 0.95 }}
                                        className="absolute -right-24 sm:right-0 top-full mt-3 w-[calc(100vw-32px)] max-w-[360px] sm:w-96 bg-white dark:bg-slate-900 sm:glass sm:bg-slate-50/95 sm:dark:bg-slate-900/95 rounded-2xl border-2 border-slate-200 dark:border-slate-700 shadow-[0_20px_50px_-12px_rgba(0,0,0,0.25)] z-50 overflow-hidden"
                                    >
                                        <div className="p-5 border-b border-slate-100 dark:border-slate-800/50 flex items-center justify-between">
                                            <h3 className="font-bold text-slate-900 dark:text-white flex items-center gap-2">
                                                Notifications
                                                {unreadCount > 0 && (
                                                    <span className="px-2 py-0.5 rounded-full bg-primary/10 text-primary text-[10px] font-black">
                                                        {unreadCount} NEW
                                                    </span>
                                                )}
                                            </h3>
                                            {unreadCount > 0 && (
                                                <button
                                                    onClick={handleMarkAllRead}
                                                    className="text-[10px] font-black text-primary hover:text-blue-600 transition-colors uppercase tracking-widest"
                                                >
                                                    Mark all read
                                                </button>
                                            )}
                                        </div>

                                        <div className="max-h-[400px] overflow-y-auto overscroll-contain">
                                            {notifications.length === 0 ? (
                                                <div className="p-10 text-center space-y-3">
                                                    <div className="w-16 h-16 bg-slate-50 dark:bg-slate-800/50 rounded-2xl flex items-center justify-center mx-auto">
                                                        <Bell className="w-8 h-8 text-slate-300" />
                                                    </div>
                                                    <p className="text-sm font-bold text-slate-400">All caught up!</p>
                                                    <p className="text-xs text-slate-500">No new notifications at the moment.</p>
                                                </div>
                                            ) : (
                                                notifications.map((notif) => (
                                                    <button
                                                        key={notif.id}
                                                        onClick={() => {
                                                            markNotificationRead(notif.id);
                                                            if (notif.link) router.push(notif.link);
                                                            setIsNotifOpen(false);
                                                        }}
                                                        className={cn(
                                                            "w-full p-4 flex gap-4 text-left hover:bg-slate-50 dark:hover:bg-white/5 transition-colors border-b border-slate-50 dark:border-slate-800/30 last:border-0 relative group",
                                                            !notif.is_read && "bg-primary/5 dark:bg-primary/5"
                                                        )}
                                                    >
                                                        <div className={cn(
                                                            "w-10 h-10 rounded-xl shrink-0 flex items-center justify-center",
                                                            notif.type === 'request' ? "bg-amber-100 text-amber-600 dark:bg-amber-500/20 dark:text-amber-400" :
                                                            notif.type === 'session' ? "bg-blue-100 text-blue-600 dark:bg-blue-500/20 dark:text-blue-400" :
                                                            notif.type === 'task' ? "bg-emerald-100 text-emerald-600 dark:bg-emerald-500/20 dark:text-emerald-400" :
                                                            notif.type === 'announcement' ? "bg-purple-100 text-purple-600 dark:bg-purple-500/20 dark:text-purple-400" :
                                                            "bg-indigo-100 text-indigo-600 dark:bg-indigo-500/20 dark:text-indigo-400"
                                                        )}>
                                                            {notif.type === 'request' && <UserPlus className="w-5 h-5" />}
                                                            {notif.type === 'session' && <Calendar className="w-5 h-5" />}
                                                            {notif.type === 'task' && <CheckSquare className="w-5 h-5" />}
                                                            {notif.type === 'announcement' && <Megaphone className="w-5 h-5" />}
                                                            {notif.type === 'message' && <MessageSquare className="w-5 h-5" />}
                                                        </div>
                                                        <div className="flex-1 min-w-0 pr-2">
                                                            <div className="flex items-center justify-between gap-2 mb-0.5">
                                                                <p className="text-sm font-bold text-slate-900 dark:text-white truncate pr-2">{notif.title}</p>
                                                                {!notif.is_read && <div className="w-2 h-2 rounded-full bg-primary shrink-0" />}
                                                            </div>
                                                            <p className="text-xs text-slate-500 dark:text-slate-400 line-clamp-2 leading-relaxed">{notif.content}</p>
                                                            <div className="flex items-center gap-2 mt-2">
                                                                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wide">
                                                                    {notif.type}
                                                                </p>
                                                                <span className="text-[10px] text-slate-300 dark:text-slate-600">&bull;</span>
                                                                <p className="text-[10px] font-medium text-slate-400">
                                                                    {timeAgo(notif.created_at)}
                                                                </p>
                                                            </div>
                                                        </div>
                                                        <div className="hidden sm:block absolute right-4 top-1/2 -translate-y-1/2 opacity-0 group-hover:opacity-100 transition-opacity">
                                                            <div className="p-1.5 rounded-lg bg-white dark:bg-slate-800 shadow-sm border border-slate-100 dark:border-slate-700">
                                                                <Check className="w-3.5 h-3.5 text-primary" />
                                                            </div>
                                                        </div>
                                                    </button>
                                                ))
                                            )}
                                        </div>

                                        {notifications.length > 0 && (
                                            <div className="p-4 border-t border-slate-100 dark:border-slate-800/50 bg-slate-50/50 dark:bg-white/5">
                                                <button
                                                    onClick={() => {
                                                        setIsNotifOpen(false);
                                                        router.push('/dashboard/settings');
                                                    }}
                                                    className="w-full text-center text-xs font-bold text-slate-500 hover:text-primary transition-colors"
                                                >
                                                    Notification Settings
                                                </button>
                                            </div>
                                        )}
                                    </motion.div>
                                )}
                            </AnimatePresence>
                        </div>

                        <button
                            onClick={handleLogout}
                            disabled={isLogoutLoading}
                            className={cn(
                                "md:hidden w-10 h-10 rounded-full flex items-center justify-center text-slate-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-950/20 transition-all border border-transparent hover:border-red-100 dark:hover:border-red-900/30",
                                isLogoutLoading && "opacity-50 cursor-not-allowed"
                            )}
                            aria-label="Logout"
                        >
                            {isLogoutLoading ? (
                                <div className="w-4 h-4 border-2 border-red-500 border-t-transparent rounded-full animate-spin" />
                            ) : (
                                <LogOut className="w-5 h-5" />
                            )}
                        </button>

                        <div className="flex items-center gap-3">
                            <div className="hidden sm:flex flex-col items-end">
                                <div className="text-[9px] font-black uppercase tracking-widest px-2 py-0.5 rounded-md bg-slate-100 dark:bg-slate-800 text-slate-500 dark:text-slate-400 border border-slate-200 dark:border-white/5">
                                    {!mounted || !profile ? 'Identifying Role...' : profile.role === 'mentor' ? 'Faculty Mentor' : profile.role === 'mentee' ? 'Mentee' : 'Member'}
                                </div>
                            </div>
                            <div className="w-10 h-10 rounded-full bg-primary/10 border-2 border-primary/20 flex items-center justify-center overflow-hidden shrink-0 shadow-sm relative group">
                                <span className="text-primary font-bold text-sm tracking-widest">{mounted ? initials : ''}</span>
                            </div>
                        </div>
                    </div>
                </header>

                {/* Page content ΓÇö no blocking here */}
                <main className={cn(
                    "flex-1 overflow-y-auto p-4 sm:p-10 pb-28 sm:pb-10 overscroll-contain",
                    isMessagesPage && "p-0 pb-20 sm:p-0 sm:pb-0"
                )}>
                    <ProtectedRoute>
                        {children}
                    </ProtectedRoute>
                </main>
            </div>

            <MobileNav />
        </div>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import { motion } from "framer-motion";
import { Plus, Search, Filter, Clock, CheckCircle2, AlertTriangle, FileText, Download, X, CircleDashed } from "lucide-react";
import { supabase } from "@/lib/supabase";
import { useAuth } from "@/contexts/AuthContext";
import { formatDate, groupItemsByDate } from "@/lib/date-utils";
import { useToast } from "@/components/Toast";
import { logger } from "@/lib/logger";

export default function LeavesPage() {
    const { user, profile, loading: authLoading } = useAuth();
    const { toast, confirm } = useToast();

    const [leaves, setLeaves] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [refreshTrigger, setRefreshTrigger] = useState(0);

    // Form State
    const [newLeave, setNewLeave] = useState({
        startDate: "",
        endDate: "",
        reason: "",
        file: null as File | null
    });

    useEffect(() => {
        if (user?.id && profile?.role) {
            fetchLeaves(user.id, profile.role);
        }
    }, [user?.id, profile?.role, refreshTrigger]);

    // Real-time synchronization
    useEffect(() => {
        if (!user?.id || !profile?.role) return;

        const channel = supabase
            .channel('medical_leaves_realtime')
            .on(
                'postgres_changes',
                {
                    event: '*',
                    schema: 'public',
                    table: 'medical_leaves',
                    filter: profile.role === 'mentee' 
                        ? `mentee_id=eq.${user.id}` 
                        : `mentor_id=eq.${user.id}`
                },
                (payload) => {
                    logger.info("LeavesPage", "Real-time update received", payload);
                    setRefreshTrigger(prev => prev + 1);
                }
            )
            .subscribe();

        return () => {
            supabase.removeChannel(channel);
        };
    }, [user?.id, profile?.role]);

    const fetchLeaves = async (userId: string, role: string) => {
        setLoading(true);
        try {
            let query = supabase.from('medical_leaves').select('*, mentee:profiles!mentee_id(full_name, student_id)');

            if (role === 'mentee') {
                query = query.eq('mentee_id', userId);
            } else if (role === 'mentor') {
                query = query.eq('mentor_id', userId);
            }

            const { data, error } = await query.order('created_at', { ascending: false });

            if (error) throw error;
            setLeaves(data || []);
        } catch (error: any) {
            logger.error("LeavesPage", "Error fetching leaves", error);
        } finally {
            setLoading(false);
        }
    };

    const handleSubmitLeave = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!user || profile?.role !== 'mentee') return;

        if (!newLeave.startDate || !newLeave.endDate || !newLeave.reason) {
            toast("Please fill in all required fields.", "warning");
            return;
        }

        setIsSubmitting(true);
        try {
            // First, find the assigned mentor
            const { data: menteeData, error: mError } = await supabase
                .from('mentees')
                .select('assigned_mentor_id')
                .eq('id', user.id)
                .single();

            if (mError || !menteeData?.assigned_mentor_id) {
                throw new Error("You must have an assigned mentor to submit a leave request.");
            }

            let reportPath = null;

            // Upload PDF if provided
            if (newLeave.file) {
                if (newLeave.file.size > 5 * 1024 * 1024) throw new Error("File must be less than 5MB");

                const fileExt = newLeave.file.name.split('.').pop();
                const fileName = `${Date.now()}_${Math.random().toString(36).substring(7)}.${fileExt}`;
                reportPath = `${user.id}/${fileName}`;

                const { error: uploadError } = await supabase.storage
                    .from('medical-reports')
                    .upload(reportPath, newLeave.file);

                if (uploadError) throw uploadError;
            }

            // Insert Database Record
            const { error: insertError } = await supabase
                .from('medical_leaves')
                .insert({
                    mentee_id: user.id,
                    mentor_id: menteeData.assigned_mentor_id,
                    start_date: newLeave.startDate,
                    end_date: newLeave.endDate,
                    reason: newLeave.reason,
                    report_file_path: reportPath
                });

            if (insertError) throw insertError;

            toast("Medical leave request submitted successfully.", "success");
            setIsModalOpen(false);
            setNewLeave({ startDate: "", endDate: "", reason: "", file: null });
            setRefreshTrigger(prev => prev + 1);

        } catch (error: any) {
            logger.error("LeavesPage", "Submit Error", error);
            toast(error.message || "Failed to submit request.", "error");
        } finally {
            setIsSubmitting(false);
        }
    };

    const handleUpdateStatus = async (id: string, newStatus: 'approved' | 'rejected') => {
        let rejectionReason = null;
        if (newStatus === 'rejected') {
            rejectionReason = prompt("Please provide a reason for rejecting this leave:");
            if (rejectionReason === null) return; // cancelled
        } else {
            const ok = await confirm({
                title: "Approve Leave",
                message: "Are you sure you want to approve this medical leave?",
                confirmText: "Approve",
                variant: "primary"
            });
            if (!ok) return;
        }

        try {
            const { error } = await supabase
                .from('medical_leaves')
                .update({
                    status: newStatus,
                    rejection_reason: rejectionReason,
                    updated_at: new Date().toISOString()
                })
                .eq('id', id);

            if (error) throw error;
            toast(`Leave request ${newStatus}.`, "success");
            setRefreshTrigger(prev => prev + 1);
        } catch (err) {
            toast("Failed to update status", "error");
        }
    };

    const handleDownloadReport = async (path: string) => {
        try {
            toast("Preparing download...", "info");
            // Determine viewing strategy based on file type. Let's try to just download it.
            const { data, error } = await supabase.storage.from('medical-reports').download(path);
            if (error) throw error;

            // Create a downloadable link out of the raw data Blob
            const url = URL.createObjectURL(data);
            const a = document.createElement('a');
            a.href = url;
            a.download = path.split('/').pop() || 'medical_report.pdf';
            document.body.appendChild(a);
            a.click();
            URL.revokeObjectURL(url);
            document.body.removeChild(a);

        } catch (error) {
            logger.error("LeavesPage", "Download Error", error);
            toast("Unable to securely download the file. Ensure you have proper permissions.", "error");
        }
    };

    if (authLoading) return null;

    return (
        <div className="space-y-6 animate-in fade-in duration-500 pb-12">
            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-6">
                <div>
                    <h1 className="text-xl sm:text-2xl font-bold text-slate-900 dark:text-white tracking-tight">
                        Medical Exceptions
                    </h1>
                    <p className="text-sm sm:text-base text-slate-500 dark:text-slate-400 mt-1">
                        {profile?.role === 'mentor' ? 'Review medical leaves from your mentees.' : 'Submit medical documents to request a leave of absence.'}
                    </p>
                </div>
                {profile?.role === 'mentee' && (
                    <button
                        onClick={() => setIsModalOpen(true)}
                        className="w-full sm:w-auto flex items-center justify-center gap-2 px-5 py-3.5 bg-gradient-to-r from-primary to-blue-600 text-white font-bold rounded-xl shadow-lg shadow-primary/20 hover:shadow-primary/40 transition-all active:scale-95">
                        <Plus className="w-5 h-5" /> Request Leave
                    </button>
                )}
            </div>

            {loading ? (
                <div className="grid grid-cols-1 gap-4">
                    {[1, 2].map(i => (
                        <div key={i} className="p-4 sm:p-5 rounded-2xl border border-slate-200/50 dark:border-white/5 bg-white/60 dark:bg-slate-900/40 shimmer-skeleton flex flex-col md:flex-row md:items-center justify-between gap-5">
                            <div className="flex items-start gap-4 flex-1">
                                <div className="w-12 h-12 rounded-[20px] bg-slate-200 dark:bg-slate-800 shrink-0" />
                                <div className="space-y-3 w-full">
                                    <div className="h-5 w-1/2 rounded-lg bg-slate-200 dark:bg-slate-800" />
                                    <div className="h-4 w-3/4 rounded-lg bg-slate-100 dark:bg-slate-800/60" />
                                    <div className="h-8 w-40 rounded-lg bg-slate-100 dark:bg-slate-800/40 mt-2" />
                                </div>
                            </div>
                            {profile?.role === 'mentor' && (
                                <div className="flex items-center gap-3 w-full md:w-auto pt-4 md:pt-0 border-t md:border-0 border-slate-100 dark:border-slate-800">
                                    <div className="h-10 w-24 rounded-xl bg-slate-100 dark:bg-slate-800/80 shrink-0" />
                                    <div className="h-10 w-24 rounded-xl bg-slate-200 dark:bg-slate-800 shrink-0" />
                                </div>
                            )}
                        </div>
                    ))}
                </div>
            ) : leaves.length === 0 ? (
                <div className="py-8 px-6 glass rounded-2xl border border-white/40 dark:border-slate-800/50 text-center space-y-4">
                    <div className="w-16 h-16 bg-slate-100 dark:bg-slate-800 rounded-2xl flex items-center justify-center mx-auto">
                        <FileText className="w-8 h-8 text-slate-300" />
                    </div>
                    <div>
                        <h3 className="text-lg font-bold text-slate-900 dark:text-white">Clean Bill of Health</h3>
                        <p className="text-sm text-slate-500">No medical leave requests found in your history.</p>
                    </div>
                </div>
            ) : (
                <div className="space-y-6">
                    {Object.entries(groupItemsByDate(leaves, l => l.created_at)).map(([date, items]) => (
                        <div key={date} className="space-y-4">
                            <div className="flex items-center gap-4">
                                <div className="h-[1px] flex-1 bg-gradient-to-r from-transparent via-slate-200 dark:via-slate-800 to-transparent" />
                                <span className="text-[11px] font-black uppercase tracking-[0.2em] text-slate-400 bg-white/50 dark:bg-slate-900/50 px-3 py-1 rounded-full backdrop-blur-md border border-slate-200/50 dark:border-white/5 shadow-sm">{date}</span>
                                <div className="h-[1px] flex-1 bg-gradient-to-r from-transparent via-slate-200 dark:via-slate-800 to-transparent" />
                            </div>
                            <div className="grid grid-cols-1 gap-4">
                                {items.map((leave, i) => (
                                    <motion.div
                                        key={leave.id}
                                        initial={{ opacity: 0, y: 10 }}
                                        animate={{ opacity: 1, y: 0 }}
                                        transition={{ delay: i * 0.05 }}
                                        className="p-4 sm:p-5 rounded-2xl border border-white/40 dark:border-slate-800/50 bg-white/60 dark:bg-slate-900/40 backdrop-blur-md shadow-sm group hover:border-primary/20 transition-all flex flex-col md:flex-row md:items-center justify-between gap-5"
                                    >
                                        <div className="flex items-start gap-4 flex-1">
                                            <div className={`w-10 h-10 rounded-xl flex items-center justify-center shrink-0 border-2 ${
                                                leave.status === 'approved' ? 'bg-emerald-500/10 text-emerald-600 border-emerald-500/20' :
                                                leave.status === 'rejected' ? 'bg-red-500/10 text-red-500 border-red-500/20' :
                                                'bg-amber-500/10 text-amber-600 border-amber-500/20'
                                            }`}>
                                                {leave.status === 'approved' ? <CheckCircle2 className="w-6 h-6" /> :
                                                 leave.status === 'rejected' ? <X className="w-6 h-6" /> :
                                                 <Clock className="w-6 h-6" />}
                                            </div>
                                            <div className="flex-1 min-w-0">
                                                <div className="flex items-center gap-2 mb-1">
                                                    <h3 className="font-bold text-slate-900 dark:text-white truncate">
                                                        {profile?.role === 'mentor' ? leave.mentee?.full_name : 'Medical Leave Request'}
                                                    </h3>
                                                    {leave.mentee?.student_id && (
                                                        <span className="text-[10px] bg-slate-100 dark:bg-slate-800 text-slate-500 px-1.5 py-0.5 rounded font-black">{leave.mentee.student_id}</span>
                                                    )}
                                                </div>
                                                <div className="flex flex-wrap items-center gap-x-4 gap-y-1 text-xs text-slate-500 font-medium">
                                                    <span className="flex items-center gap-1.5"><FileText className="w-3.5 h-3.5 text-slate-400" /> {leave.reason}</span>
                                                    <span className="flex items-center gap-1.5 text-slate-400">
                                                        {formatDate(leave.start_date)} ΓÇö {formatDate(leave.end_date)}
                                                    </span>
                                                </div>
                                                
                                                {leave.status === 'rejected' && leave.rejection_reason && (
                                                    <div className="mt-3 p-3 rounded-xl bg-red-500/5 border border-red-500/10">
                                                        <p className="text-[10px] font-black uppercase text-red-500/60 mb-1">Mentor Feedback</p>
                                                        <p className="text-xs text-red-600/80 italic font-medium">&quot;{leave.rejection_reason}&quot;</p>
                                                    </div>
                                                )}

                                                {leave.report_file_path && (
                                                    <button
                                                        onClick={() => handleDownloadReport(leave.report_file_path)}
                                                        className="mt-3 flex items-center gap-1.5 text-[10px] font-black uppercase tracking-widest text-primary hover:text-blue-600 transition-colors bg-primary/5 dark:bg-primary/10 px-3 py-1.5 rounded-lg w-max border border-primary/10"
                                                    >
                                                        <Download className="w-3.5 h-3.5" /> View Medical Report
                                                    </button>
                                                )}
                                            </div>
                                        </div>

                                        <div className="flex items-center gap-3 w-full md:w-auto pt-4 md:pt-0 border-t md:border-0 border-slate-100 dark:border-slate-800 shrink-0">
                                            {profile?.role === 'mentor' && leave.status === 'pending' ? (
                                                <>
                                                    <button 
                                                        onClick={() => handleUpdateStatus(leave.id, 'rejected')}
                                                        className="flex-1 md:flex-none px-5 py-2.5 bg-slate-50 hover:bg-red-50 text-slate-500 hover:text-red-500 rounded-xl font-bold text-xs border border-slate-200 hover:border-red-200 transition-all active:scale-95"
                                                    >Reject</button>
                                                    <button 
                                                        onClick={() => handleUpdateStatus(leave.id, 'approved')}
                                                        className="flex-1 md:flex-none px-6 py-2.5 bg-primary text-white hover:bg-blue-600 rounded-xl font-bold text-xs shadow-lg shadow-primary/20 transition-all active:scale-95"
                                                    >Approve</button>
                                                </>
                                            ) : (
                                                <div className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest border ${
                                                    leave.status === 'approved' ? 'bg-emerald-500/5 text-emerald-500 border-emerald-500/20' :
                                                    leave.status === 'rejected' ? 'bg-red-500/5 text-red-500 border-red-500/20' :
                                                    'bg-amber-500/5 text-amber-500 border-amber-500/20'
                                                }`}>
                                                    {leave.status}
                                                </div>
                                            )}
                                        </div>
                                    </motion.div>
                                ))}
                            </div>
                        </div>
                    ))}
                </div>
            )}

            {/* Request Modal */}
            {isModalOpen && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/50 backdrop-blur-sm">
                    <motion.div
                        initial={{ opacity: 0, scale: 0.95 }}
                        animate={{ opacity: 1, scale: 1 }}
                        className="bg-white dark:bg-slate-900 rounded-2xl w-full max-w-lg shadow-2xl overflow-hidden"
                    >
                        <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between">
                            <h2 className="text-xl font-bold text-slate-900 dark:text-white flex items-center gap-2"><FileText className="w-6 h-6 text-primary" /> Request Leave</h2>
                            <button onClick={() => setIsModalOpen(false)} className="p-2 text-slate-400 hover:text-slate-600 rounded-full hover:bg-slate-100 active:scale-90 transition-all">
                                <X className="w-5 h-5" />
                            </button>
                        </div>

                        <form onSubmit={handleSubmitLeave} className="p-6 space-y-4">
                            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-1.5 pl-1">Start Date</label>
                                    <input
                                        type="date"
                                        required
                                        value={newLeave.startDate}
                                        onChange={(e) => setNewLeave({ ...newLeave, startDate: e.target.value })}
                                        className="w-full px-4 py-3 rounded-xl bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 outline-none focus:border-primary text-sm"
                                    />
                                </div>
                                <div>
                                    <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-1.5 pl-1">End Date</label>
                                    <input
                                        type="date"
                                        required
                                        min={newLeave.startDate}
                                        value={newLeave.endDate}
                                        onChange={(e) => setNewLeave({ ...newLeave, endDate: e.target.value })}
                                        className="w-full px-4 py-3 rounded-xl bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 outline-none focus:border-primary text-sm"
                                    />
                                </div>
                            </div>

                            <div>
                                <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-1.5 pl-1">Reason for Leave</label>
                                <textarea
                                    required
                                    rows={3}
                                    value={newLeave.reason}
                                    onChange={(e) => setNewLeave({ ...newLeave, reason: e.target.value })}
                                    className="w-full px-4 py-3 rounded-xl bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 outline-none focus:border-primary text-sm resize-none"
                                    placeholder="Briefly explain your medical situation..."
                                />
                            </div>

                            <div>
                                <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-1.5 pl-1">Medical Report (PDF/Image)</label>
                                <input
                                    type="file"
                                    accept=".pdf,image/*"
                                    onChange={(e) => setNewLeave({ ...newLeave, file: e.target.files?.[0] || null })}
                                    className="w-full px-4 py-2.5 rounded-xl bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 text-sm file:mr-4 file:py-2 file:px-4 file:rounded-lg file:border-0 file:text-xs file:font-black file:bg-primary file:text-white hover:file:bg-blue-600 transition-all cursor-pointer"
                                />
                                <p className="text-[10px] text-slate-400 mt-1.5 pl-1 font-medium italic">Highly confidential. Only your officially assigned mentor can view this document. Max 5MB.</p>
                            </div>

                            <div className="pt-4 flex gap-3">
                                <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 px-4 py-3 rounded-xl border border-slate-200 font-bold hover:bg-slate-50 active:scale-95 transition-all text-sm text-slate-600 dark:text-slate-400">
                                    Cancel
                                </button>
                                <button type="submit" disabled={isSubmitting} className="flex-1 px-4 py-3 rounded-xl bg-primary text-white font-bold hover:bg-blue-700 active:scale-95 shadow-lg shadow-primary/20 transition-all disabled:opacity-50 flex justify-center items-center">
                                    {isSubmitting ? <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin" /> : "Submit Request"}
                                </button>
                            </div>
                        </form>
                    </motion.div>
                </div>
            )}
        </div>
    );
}

/**
 * @file dashboard/mentees/detail/MenteeDetailClient.tsx
 * @description Client-side logic for the Mentee detail page.
 */

"use client";

import React, { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import {
    ArrowLeft, Mail, Calendar, CheckSquare, StickyNote,
    Trash2, Clock, AlertCircle, ChevronRight,
    FileText, TrendingUp, Video, Send, X, Download, Users, Phone, Briefcase, User
} from "lucide-react";
import { downloadCSV } from "@/lib/csv-export";
import { supabase } from "@/lib/supabase";
import { useAuth } from "@/contexts/AuthContext";
import { useRouter } from "next/navigation";
import { useToast } from "@/components/Toast";
import { logger } from "@/lib/logger";
import { getInitials, groupItemsByDate } from "@/lib/date-utils";

function fmtDate(d: string | null | undefined) {
    if (!d) return "N/A";
    const date = new Date(d);
    if (isNaN(date.getTime())) return "Invalid Date";
    return date.toLocaleDateString("en-IN", { day: "numeric", month: "short", year: "numeric" });
}
function fmtTime(d: string | null | undefined) {
    if (!d) return "N/A";
    const date = new Date(d);
    if (isNaN(date.getTime())) return "Invalid Date";
    return date.toLocaleTimeString("en-IN", { hour: "2-digit", minute: "2-digit" });
}
function timeAgo(d: string) {
    const diff = Date.now() - new Date(d).getTime();
    const mins = Math.floor(diff / 60000);
    if (mins < 1) return "just now";
    if (mins < 60) return `${mins}m ago`;
    const hrs = Math.floor(mins / 60);
    if (hrs < 24) return `${hrs}h ago`;
    return `${Math.floor(hrs / 24)}d ago`;
}

type Section = "profile" | "sessions" | "tasks" | "notes";

export default function MenteeDetailClient({ id }: { id: string }) {
    const router = useRouter();
    const { user, profile, loading: authLoading } = useAuth();
    const { toast, confirm } = useToast();

    const [loading, setLoading] = useState(true);
    const [mentee, setMentee] = useState<any>(null);
    const [sessions, setSessions] = useState<any[]>([]);
    const [tasks, setTasks] = useState<any[]>([]);
    const [notes, setNotes] = useState<any[]>([]);
    const [activeSection, setActiveSection] = useState<Section>("profile");

    const [noteInput, setNoteInput] = useState("");
    const [isSavingNote, setIsSavingNote] = useState(false);

    // Auth guard
    useEffect(() => {
        if (!authLoading && profile?.role !== "mentor") {
            router.replace("/dashboard");
        }
    }, [authLoading, profile]);

    useEffect(() => {
        if (!user?.id || !id || authLoading) return;
        fetchAll();
    }, [user?.id, id, authLoading]);

    const fetchAll = async () => {
        setLoading(true);
        try {
            const [profileRes, menteeRes, sessionsRes, tasksRes, notesRes] = await Promise.all([
                supabase
                    .from("profiles")
                    .select("id, full_name, email, student_id, bio")
                    .eq("id", id)
                    .maybeSingle(),
                supabase
                    .from("mentees")
                    .select("father_name, mother_name, father_mobile, mother_mobile, father_occupation, mother_occupation, career_goals, semester, section")
                    .eq("id", id)
                    .maybeSingle(),
                supabase
                    .from("sessions")
                    .select("id, title, scheduled_at, duration_minutes, session_type, meeting_link")
                    .eq("mentor_id", user!.id)
                    .eq("mentee_id", id)
                    .order("scheduled_at", { ascending: false })
                    .limit(20),
                supabase
                    .from("assignments")
                    .select("id, title, description, status, due_date, task_type, form_data")
                    .eq("mentee_id", id)
                    .order("created_at", { ascending: false }),
                supabase
                    .from("mentor_notes")
                    .select("id, content, created_at")
                    .eq("mentor_id", user!.id)
                    .eq("mentee_id", id)
                    .order("created_at", { ascending: false })
            ]);

            if (profileRes.data) {
                setMentee({
                    ...profileRes.data,
                    ...(menteeRes.data || {})
                });
            }

            setSessions(sessionsRes.data || []);
            setTasks(tasksRes.data || []);
            setNotes(notesRes.data || []);
        } catch (e) {
            logger.error("MenteeDetailClient", "Fetch error", e);
        } finally {
            setLoading(false);
        }
    };

    const handleSaveNote = async () => {
        if (!noteInput.trim()) return;
        setIsSavingNote(true);
        try {
            const { data, error } = await supabase.from("mentor_notes").insert({
                mentor_id: user!.id,
                mentee_id: id,
                content: noteInput.trim(),
            }).select().single();
            if (error) throw error;
            setNotes(prev => [data, ...prev]);
            setNoteInput("");
            toast("Note saved.", "success");
        } catch (e: any) {
            toast(e.message || "Failed to save note.", "error");
        } finally {
            setIsSavingNote(false);
        }
    };

    const handleDeleteNote = async (noteId: string) => {
        const ok = await confirm({ title: "Delete Note", message: "Delete this private note permanently?", confirmText: "Delete", variant: "danger" });
        if (!ok) return;
        try {
            await supabase.from("mentor_notes").delete().eq("id", noteId);
            setNotes(prev => prev.filter(n => n.id !== noteId));
        } catch (e: any) {
            toast(e.message || "Failed to delete note.", "error");
        }
    };

    const handleExportTasks = () => {
        if (!tasks.length) {
            toast("No tasks to export.", "info");
            return;
        }

        // Flatten tasks and their form_data for CSV
        const flattened = tasks.map(t => {
            const base = {
                title: t.title,
                status: t.status,
                due_date: t.due_date ? fmtDate(t.due_date) : "No Due Date",
                task_type: t.task_type || "general",
                description: t.description || ""
            };

            // If it's a result or placement task, attempt to serialize the form_data
            if (t.form_data) {
                if (t.task_type === "result") {
                    const fd = t.form_data;
                    return {
                        ...base,
                        cgpa: fd.cgpa || "",
                        sgpa: fd.sgpa || "",
                        subjects: (fd.subjects || []).map((s: any) => `${s.name}(${s.code || 'N/A'}): ${s.marks || s.grade || 'N/A'}`).join('; ')
                    };
                }
                if (t.task_type === "placement") {
                    const fd = t.form_data;
                    return {
                        ...base,
                        company: fd.company || "",
                        role: fd.role || "",
                        package: fd.package || "",
                        location: fd.location || ""
                    };
                }
                // Fallback for other form data
                return { ...base, response: JSON.stringify(t.form_data) };
            }

            return base;
        });

        downloadCSV(flattened, `${mentee?.full_name || 'Mentee'}_Tasks_${new Date().toISOString().split('T')[0]}.csv`);
        toast("Exported task records.", "success");
    };

    const handleBack = () => router.push("/dashboard/mentees");

    const taskCompleted = tasks.filter(t => ["submitted", "reviewed"].includes(t.status)).length;
    const taskProgress = tasks.length > 0 ? Math.round((taskCompleted / tasks.length) * 100) : 0;
    const now = new Date();
    const upcomingSessions = sessions.filter(s => new Date(s.scheduled_at) >= now).length;

    if (!authLoading && profile?.role !== "mentor") return null;

    return (
        <div className="space-y-6 animate-in fade-in duration-500 pb-20 max-w-4xl">

            {/* Back */}
            <button
                onClick={handleBack}
                className="flex items-center gap-2 text-sm font-bold text-slate-500 hover:text-primary transition-colors group"
            >
                <ArrowLeft className="w-4 h-4 group-hover:-translate-x-0.5 transition-transform" />
                Back to Mentees
            </button>

            {/* Profile Hero */}
            {loading ? (
                <div className="h-60 w-full glass rounded-2xl shimmer-skeleton" />
            ) : mentee ? (
                <motion.div
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    className="glass p-5 sm:p-6 rounded-2xl border border-white/40 dark:border-slate-800/50"
                >
                    <div className="flex flex-col sm:flex-row items-start sm:items-center gap-5">
                        <div className="w-12 h-12 rounded-xl bg-gradient-to-br from-primary/20 to-blue-500/20 flex items-center justify-center text-primary font-black text-xl shrink-0">
                            {getInitials(mentee.full_name)}
                        </div>
                        <div className="flex-1 min-w-0">
                            <h1 className="text-xl sm:text-2xl font-black text-slate-900 dark:text-white">{mentee.full_name}</h1>
                            <div className="flex flex-wrap items-center gap-2 mt-1">
                                {mentee.student_id && (
                                    <span className="text-[11px] bg-primary/10 text-primary px-2 py-0.5 rounded-md font-black uppercase tracking-wider">{mentee.student_id}</span>
                                )}
                                <a href={`mailto:${mentee.email}`} className="flex items-center gap-1 text-xs text-slate-500 hover:text-primary transition-colors font-medium">
                                    <Mail className="w-3 h-3" /> {mentee.email}
                                </a>
                            </div>
                            {mentee.bio && <p className="text-sm text-slate-500 mt-2 leading-relaxed">{mentee.bio}</p>}
                        </div>

                        {/* Mini stats */}
                        <div className="flex gap-4 shrink-0">
                            <div className="text-center">
                                <p className="text-xl font-black text-primary">{taskProgress}%</p>
                                <p className="text-[10px] font-black uppercase tracking-widest text-slate-400">Tasks</p>
                            </div>
                            <div className="text-center">
                                <p className="text-xl font-black text-emerald-500">{upcomingSessions}</p>
                                <p className="text-[10px] font-black uppercase tracking-widest text-slate-400">Upcoming</p>
                            </div>
                            <div className="text-center">
                                <p className="text-xl font-black text-indigo-500">{notes.length}</p>
                                <p className="text-[10px] font-black uppercase tracking-widest text-slate-400">Notes</p>
                            </div>
                        </div>
                    </div>

                    {/* Progress Bar */}
                    <div className="mt-6">
                        <div className="flex justify-between text-[10px] font-black uppercase tracking-widest text-slate-400 mb-2">
                            <span>Overall Task Progress</span>
                            <span className="text-primary">{taskProgress}%</span>
                        </div>
                        <div className="h-2 bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden">
                            <motion.div
                                initial={{ width: 0 }}
                                animate={{ width: `${taskProgress}%` }}
                                transition={{ duration: 1, ease: "easeOut" }}
                                className="h-full bg-gradient-to-r from-primary to-blue-500 rounded-full"
                            />
                        </div>
                    </div>
                </motion.div>
            ) : (
                <div className="flex items-center gap-3 p-6 glass rounded-2xl border border-red-200 dark:border-red-800/40">
                    <AlertCircle className="w-5 h-5 text-red-500" />
                    <p className="text-sm font-bold text-red-600">Mentee profile not found.</p>
                </div>
            )}

            {/* Section Tabs */}
            <div className="flex gap-2 bg-slate-100 dark:bg-slate-800/50 p-1 rounded-2xl w-full sm:w-fit overflow-x-auto no-scrollbar">
                {(["profile", "sessions", "tasks", "notes"] as Section[]).map(s => (
                    <button
                        key={s}
                        onClick={() => setActiveSection(s)}
                        className={`px-4 py-2 rounded-xl text-sm font-bold capitalize transition-all ${activeSection === s
                            ? "bg-white dark:bg-slate-800 text-primary shadow-sm"
                            : "text-slate-500 hover:text-slate-700 dark:hover:text-slate-300"
                            }`}
                    >
                        {s === "profile" && <User className="w-3.5 h-3.5 inline mr-1.5 -mt-0.5" />}
                        {s === "sessions" && <Calendar className="w-3.5 h-3.5 inline mr-1.5 -mt-0.5" />}
                        {s === "tasks" && <CheckSquare className="w-3.5 h-3.5 inline mr-1.5 -mt-0.5" />}
                        {s === "notes" && <StickyNote className="w-3.5 h-3.5 inline mr-1.5 -mt-0.5" />}
                        {s}
                        {s === "notes" && notes.length > 0 && (
                            <span className="ml-1.5 bg-primary text-white text-[9px] font-black px-1.5 py-0.5 rounded-full">{notes.length}</span>
                        )}
                    </button>
                ))}
            </div>

            <AnimatePresence mode="wait">
                {activeSection === "profile" && (
                    <motion.div key="profile" initial={{ opacity: 0, y: 6 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0 }} className="space-y-6">
                        {/* Parent Information Card */}
                        <div className="glass p-5 rounded-2xl border border-white/40 dark:border-slate-800/50 space-y-5">
                            <div className="flex items-center gap-2 mb-2">
                                <Users className="w-5 h-5 text-primary" />
                                <h3 className="text-lg font-bold text-slate-800 dark:text-white">Parent Information</h3>
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <ParentInfoCard 
                                    label="Father's Details" 
                                    name={mentee?.father_name} 
                                    mobile={mentee?.father_mobile} 
                                    occupation={mentee?.father_occupation} 
                                />
                                <ParentInfoCard 
                                    label="Mother's Details" 
                                    name={mentee?.mother_name} 
                                    mobile={mentee?.mother_mobile} 
                                    occupation={mentee?.mother_occupation} 
                                />
                            </div>
                        </div>

                        {/* Academic & Career Goals */}
                        <div className="glass p-5 rounded-2xl border border-white/40 dark:border-slate-800/50 space-y-4">
                            <div className="flex items-center gap-2 mb-2">
                                <TrendingUp className="w-5 h-5 text-indigo-500" />
                                <h3 className="text-lg font-bold text-slate-800 dark:text-white">Academic & Career Goals</h3>
                            </div>
                            <div className="space-y-3">
                                <div className="p-4 rounded-xl bg-slate-50 dark:bg-slate-900/50 border border-slate-100 dark:border-white/5">
                                    <p className="text-[10px] font-black uppercase tracking-widest text-slate-400 mb-1">Career Goals</p>
                                    <p className="text-sm font-medium text-slate-700 dark:text-slate-300 leading-relaxed">
                                        {mentee?.career_goals || "No career goals specified yet."}
                                    </p>
                                </div>
                                <div className="grid grid-cols-2 gap-4">
                                    <div className="p-4 rounded-xl bg-slate-50 dark:bg-slate-900/50 border border-slate-100 dark:border-white/5">
                                        <p className="text-[10px] font-black uppercase tracking-widest text-slate-400 mb-1">Semester</p>
                                        <p className="text-sm font-bold text-slate-900 dark:text-white">{mentee?.semester || "N/A"}</p>
                                    </div>
                                    <div className="p-4 rounded-xl bg-slate-50 dark:bg-slate-900/50 border border-slate-100 dark:border-white/5">
                                        <p className="text-[10px] font-black uppercase tracking-widest text-slate-400 mb-1">Section</p>
                                        <p className="text-sm font-bold text-slate-900 dark:text-white">{mentee?.section || "N/A"}</p>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </motion.div>
                )}
                {activeSection === "sessions" && (
                    <motion.div key="sessions" initial={{ opacity: 0, y: 6 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0 }} className="space-y-8">
                        {loading ? (
                            <div className="space-y-3">{[1, 2, 3].map(i => <div key={i} className="h-20 shimmer-skeleton rounded-2xl" />)}</div>
                        ) : sessions.length === 0 ? (
                            <div className="text-center py-10 text-slate-400">
                                <Calendar className="w-9 h-9 mx-auto mb-2 text-slate-200 dark:text-slate-700" />
                                <p className="text-sm font-semibold">No sessions recorded yet.</p>
                            </div>
                        ) : (
                            <div className="space-y-8">
                                {Object.entries(groupItemsByDate(sessions, s => s.scheduled_at)).map(([date, items]) => (
                                    <div key={date} className="space-y-4">
