                    {data.cgpa && <span><strong className="text-indigo-600 dark:text-indigo-400 font-black">CGPA:</strong> {data.cgpa}</span>}
                    {data.sgpa && <span><strong className="text-indigo-600 dark:text-indigo-400 font-black">SGPA:</strong> {data.sgpa}</span>}
