/**
 * @file dashboard/mentees/page.tsx
 * @description Compact mentee directory ΓÇö replaces big cards with a fast,
 * searchable list. Clicking a row navigates to the full mentee detail page.
 */

"use client";

import React, { useState, useEffect } from "react";
import { motion } from "framer-motion";
import { Search, Plus, X, BookOpen, Users, AlertCircle, ChevronRight, TrendingUp } from "lucide-react";
import { supabase } from "@/lib/supabase";
import { useRouter } from "next/navigation";
import Link from "next/link";
import { useAuth } from "@/contexts/AuthContext";
import { getInitials } from "@/lib/date-utils";
import { useToast } from "@/components/Toast";
import { logger } from "@/lib/logger";
import { downloadCSV } from "@/lib/csv-export";
import { Clock } from "lucide-react";

export default function MenteesPage() {
    const router = useRouter();
    const [searchTerm, setSearchTerm] = useState("");
    const [debouncedTerm, setDebouncedTerm] = useState("");
    const { profile, loading: authLoading, globalData, updateGlobalData, user } = useAuth();
    const { toast, confirm } = useToast();

    const [mentees, setMentees] = useState<any[]>(globalData.mentees || []);
    const [loading, setLoading] = useState(() => !globalData.mentees || globalData.mentees.length === 0);
    const [refreshTrigger, setRefreshTrigger] = useState(0);
    const [sentRequests, setSentRequests] = useState<any[]>([]);

    const [isAddModalOpen, setIsAddModalOpen] = useState(false);
    const [searchRollNo, setSearchRollNo] = useState("");
    const [searchResult, setSearchResult] = useState<any | null>(null);
    const [isSearching, setIsSearching] = useState(false);
    const [isAssigning, setIsAssigning] = useState(false);

    useEffect(() => {
        const timer = setTimeout(() => setDebouncedTerm(searchTerm), 300);
        return () => clearTimeout(timer);
    }, [searchTerm]);

    useEffect(() => {
        if (!loading) return;
        const t = setTimeout(() => setLoading(false), 5000);
        return () => clearTimeout(t);
    }, [loading]);

    useEffect(() => {
        if (authLoading) return;
        if (profile?.role === "mentee") { router.replace("/dashboard"); return; }

        // ≡ƒƒó REAL-TIME SUBSCRIPTION
        const channel = supabase
            .channel('mentees-realtime')
            .on(
                'postgres_changes',
                { event: '*', schema: 'public', table: 'mentees' },
                () => {
                    logger.debug("MenteesPage", "Mentees table changed, refreshing...");
                    setRefreshTrigger(prev => prev + 1);
                }
            )
            .subscribe();

        const fetchData = async () => {
            if (!user) return;
            if (globalData.mentees.length > 0) setMentees(globalData.mentees);

            try {
                const { data: menteesData, error: mError } = await supabase
                    .from("mentees")
                    .select("id, profiles:profiles!fk_mentee_profile(id, full_name, email, student_id)")
                    .eq("assigned_mentor_id", user.id);

                if (mError) throw mError;

                const { data: requestsData } = await supabase
                    .from("mentor_requests")
                    .select("*, mentee:profiles!mentee_id(full_name, student_id)")
                    .eq("mentor_id", user.id)
                    .in("status", ["pending", "rejected"])
                    .order("updated_at", { ascending: false });

                if (menteesData && menteesData.length > 0) {
                    const menteeIds = menteesData.map((m: any) => m.id);
                    const { data: allAssignments } = await supabase
                        .from("assignments")
                        .select("mentee_id, status")
                        .in("mentee_id", menteeIds);

                    const formatted = menteesData.map((m: any) => {
                        const mA = allAssignments?.filter((a: any) => a.mentee_id === m.id) || [];
                        const done = mA.filter((a: any) => ["submitted", "reviewed"].includes(a.status)).length;
                        const progress = mA.length > 0 ? Math.round((done / mA.length) * 100) : 0;
                        const p = m.profiles as any;
                        const name = p?.full_name || "Mentee";
                        return {
                            id: m.id,
                            profileId: p?.id || m.id,
                            name,
                            email: p?.email || "",
                            student_id: p?.student_id || "",
                            initials: getInitials(name),
                            progress,
                        };
                    });

                    if (JSON.stringify(formatted) !== JSON.stringify(mentees)) {
                        setMentees(formatted);
                        updateGlobalData("mentees", formatted);
                    }
                } else if (menteesData?.length === 0) {
                    setMentees([]);
                    updateGlobalData("mentees", []);
                }

                if (requestsData) setSentRequests(requestsData);
            } catch (err: any) {
                logger.error("MenteesPage", "Fetch failed", err);
            } finally {
                setLoading(false);
            }
        };
        fetchData();

        return () => {
            supabase.removeChannel(channel);
        };
    }, [refreshTrigger, user, authLoading, profile?.role]);

    const handleExport = () => {
        if (!mentees.length) { toast("No records to export", "info"); return; }
        downloadCSV(mentees.map(m => ({
            "Full Name": m.name,
            "Roll Number": m.student_id,
            "Email": m.email,
            "Progress (%)": m.progress,
        })), `Mentee_Directory_${new Date().toLocaleDateString()}.csv`);
        toast("Exported!", "success");
    };

    const handleSearchMentee = async (e: React.FormEvent) => {
        e.preventDefault();
        if (profile?.role !== "mentor") { toast("Unauthorized", "error"); return; }
        const roll = searchRollNo.trim().toUpperCase();
        if (!roll) return;
        setIsSearching(true);
        setSearchResult(null);
        try {
            const { data: exactMatch } = await supabase
                .from("profiles")
                .select("id, full_name, student_id, email, role, mentorship:mentees!id(assigned_mentor_id)")
                .ilike("student_id", roll)
                .eq("role", "mentee")
                .maybeSingle();

            if (exactMatch) {
                const m = (exactMatch as any).mentorship;
                if (m?.assigned_mentor_id) { setSearchResult("assigned"); }
                else { const { mentorship, ...p } = exactMatch as any; setSearchResult(p); }
            } else {
                setSearchResult("not_found");
            }
        } catch (err: any) {
            toast("Search failed. Check your connection.", "error");
            setSearchResult("not_found");
        } finally {
            setIsSearching(false);
        }
    };

    const handleAssignMentee = async (menteeId: string) => {
        if (!user || profile?.role !== "mentor" || !searchResult) return;
        setIsAssigning(true);
        try {
            const { error } = await supabase.from("mentor_requests").insert({
                mentor_id: user.id,
                mentee_id: menteeId,
                status: "pending",
            });
            if (error) throw error;
            await supabase.from("notifications").insert({
                recipient_id: menteeId,
                type: "request",
                title: "New Mentor Connection",
                content: `${profile.full_name} wants to be your mentor.`,
                link: "/dashboard",
                is_read: false,
            });
            toast(`Request sent to ${searchResult.full_name}!`, "success");
            setIsAddModalOpen(false);
            setSearchResult(null);
            setSearchRollNo("");
            setRefreshTrigger(p => p + 1);
        } catch (err: any) {
            toast(err.message || "Failed to send request", "error");
        } finally {
            setIsAssigning(false);
        }
    };

    const filtered = mentees.filter(m =>
        m.name.toLowerCase().includes(debouncedTerm.toLowerCase()) ||
        m.email.toLowerCase().includes(debouncedTerm.toLowerCase()) ||
        m.student_id.toLowerCase().includes(debouncedTerm.toLowerCase())
    );

    const avgProgress = filtered.length > 0
        ? Math.round(filtered.reduce((a, m) => a + m.progress, 0) / filtered.length)
        : 0;

    if (!authLoading && profile && profile.role !== "mentor") {
        return (
            <div className="h-[60vh] flex flex-col items-center justify-center space-y-4">
                <AlertCircle className="w-8 h-8 text-red-400" />
                <p className="font-bold text-slate-900 dark:text-white">Access Restricted</p>
                <button onClick={() => router.push("/dashboard")} className="px-5 py-2 bg-primary text-white rounded-xl font-bold">Back</button>
            </div>
        );
    }

    return (
        <div className="space-y-7 animate-in fade-in duration-500 pb-20">

            {/* Header */}
            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
                <div>
                    <h1 className="text-xl sm:text-2xl font-bold text-slate-900 dark:text-white tracking-tight">Mentee Directory</h1>
                    <p className="text-[11px] sm:text-sm text-slate-500 dark:text-slate-400 mt-1">{mentees.length} assigned mentees</p>
                </div>
                <div className="flex items-center gap-2 flex-wrap">
                    <button onClick={handleExport} className="flex items-center gap-2 px-3.5 py-2 bg-white dark:bg-slate-900/60 text-slate-600 dark:text-slate-300 font-bold rounded-xl border border-slate-200/50 dark:border-white/5 hover:bg-slate-50 dark:hover:bg-white/5 transition-all text-xs">
                        <BookOpen className="w-4 h-4 text-primary" /> Export
                    </button>
                    <button onClick={() => setIsAddModalOpen(true)} className="flex items-center gap-2 px-4 py-2 bg-gradient-to-r from-primary to-blue-600 text-white font-bold rounded-xl shadow-lg shadow-primary/20 hover:shadow-primary/40 transition-all active:scale-95 text-xs">
                        <Plus className="w-4 h-4" /> Add Mentee
                    </button>
                </div>
            </div>

            {/* Stats Row */}
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                <div className="glass p-3.5 rounded-2xl border border-white/40 dark:border-slate-800/50 text-center">
                    <p className="text-2xl font-black text-primary">{mentees.length}</p>
                    <p className="text-[10px] font-black uppercase tracking-widest text-slate-400 mt-0.5">Assigned</p>
                </div>
                <div className="glass p-3.5 rounded-2xl border border-white/40 dark:border-slate-800/50 text-center">
                    <p className="text-2xl font-black text-emerald-500">{avgProgress}%</p>
                    <p className="text-[10px] font-black uppercase tracking-widest text-slate-400 mt-0.5">Avg Progress</p>
                </div>
                <div className="glass p-3.5 rounded-2xl border border-white/40 dark:border-slate-800/50 text-center">
                    <p className="text-2xl font-black text-amber-500">{sentRequests.filter(r => r.status === "pending").length}</p>
                    <p className="text-[10px] font-black uppercase tracking-widest text-slate-400 mt-0.5">Pending</p>
                </div>
            </div>

            {/* Search */}
            <div className="relative">
                <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                <input
                    type="text"
                    placeholder="Search by name, email, or roll number..."
