                                        </div>
                                    </div>
                                    <button onClick={() => handleAssignMentee(searchResult.id)} disabled={isAssigning} className="px-4 py-2 bg-primary text-white text-sm font-black rounded-xl hover:bg-blue-700 disabled:opacity-50 active:scale-95 transition-all">
