                            {searchResult === "assigned" && <p className="text-sm text-center text-amber-600 bg-amber-50 dark:bg-amber-950/20 p-3 rounded-2xl border border-amber-100 dark:border-amber-500/20">This mentee is already assigned to another mentor.</p>}
                        </div>
                    </motion.div>
                </div>
            )}
        </div>
    );
}

"use client";

