/**
 * @file dashboard/messages/page.tsx
 * @description Real-time secure messaging page.
 *
 * Mentors can message any of their assigned mentees.
 * Mentees can message their assigned mentor and peer students (rate-limited).
 * Peer-to-peer messages are physically purged from storage after 7 days.
 * Messages are stored in the Supabase `messages` table with real-time
 * subscriptions via Supabase Realtime channels.
 */

"use client";

import React, { useState, useEffect, useRef } from "react";
import { Search, Send, ChevronLeft, X, MessageSquare, Info, GraduationCap, Briefcase, CheckCheck } from "lucide-react";
import { motion } from "framer-motion";

import { supabase } from "@/lib/supabase";
import { cn } from "@/lib/utils";
import { useAuth } from "@/contexts/AuthContext";
import { getInitials } from "@/lib/date-utils";
import { useToast } from "@/components/Toast";
import { logger } from "@/lib/logger";
// Removed unused types


type ChatUser = {
    id: string;
    name: string;
    role: string;
    avatar: string;
    isPinnedMentor?: boolean;
    student_id?: string;
};

type Message = {
    id?: string;
    sender_id: string;
    receiver_id: string;
    content: string;
    created_at: string;
    status?: 'sending' | 'sent' | 'error';
};

export default function MessagesPage() {
    const { user, profile, globalData, loading: authLoading } = useAuth();
    const { toast } = useToast();

    // SWR initialization: If we already have mentees in globalData, use them immediately to prevent skeleton flash
    const [chatUsers, setChatUsers] = useState<ChatUser[]>(() => {
        if (profile?.role === 'mentor' && globalData.myMentees?.length > 0) {
            return globalData.myMentees.map((m: any) => ({
                id: m.profileId || m.id,
                name: m.name,
                role: 'mentee',
                avatar: getInitials(m.name),
                student_id: m.student_id
            }));
        }
        if (profile?.role === 'mentee' && globalData.myMentor) {
            return [{
                id: globalData.myMentor.id,
                name: globalData.myMentor.name,
                role: globalData.myMentor.role,
                avatar: getInitials(globalData.myMentor.name),
                isPinnedMentor: true
            }];
        }
        return [];
    });
    const [activeChat, setActiveChat] = useState<ChatUser | null>(null);
    const [searchQuery, setSearchQuery] = useState("");
    const [filteredUsers, setFilteredUsers] = useState<ChatUser[]>([]);

    // Local filtering as user types
    useEffect(() => {
        if (!searchQuery.trim()) {
            setFilteredUsers(chatUsers);
            return;
        }
        const lowerQuery = searchQuery.toLowerCase();
        const filtered = chatUsers.filter(u =>
            u.name.toLowerCase().includes(lowerQuery) ||
            (u.student_id && u.student_id.toLowerCase().includes(lowerQuery))
        );
        setFilteredUsers(filtered);
    }, [searchQuery, chatUsers]);

    // Update filtered users when chatUsers changes (e.g. on load)
    useEffect(() => {
        setFilteredUsers(chatUsers);
    }, [chatUsers]);

    // Messaging State
    const [messages, setMessages] = useState<Message[]>([]);
    const [messagesLoading, setMessagesLoading] = useState(false);
    const [newMessage, setNewMessage] = useState("");

    const [loading, setLoading] = useState(() => {
        // CONTENT-FIRST: If we have cached contacts, don't block the UI.
        const hasCachedMentees = profile?.role === 'mentor' && globalData.myMentees?.length > 0;
        const hasCachedMentor = profile?.role === 'mentee' && globalData.myMentor;
        return !(hasCachedMentees || hasCachedMentor);
    });
    const [showMobileThread, setShowMobileThread] = useState(false);
    const [showProfile, setShowProfile] = useState(false);

    // Full profile details for the active chat contact (for the profile strip)
    const [activeChatProfile, setActiveChatProfile] = useState<{
        bio?: string | null;
        student_id?: string | null;
        department?: string | null;
        designation?: string | null;
        employee_id?: string | null;
        email?: string | null;
    } | null>(null);

    // Failsafe: max 10 seconds ΓÇö matches AuthContext timeout
    useEffect(() => {
        if (!loading) return;
        const timeout = setTimeout(() => {
            logger.warn("MessagesPage", "Failsafe: Loading took too long, forcing resolution.");
            setLoading(false);
        }, 10000);
        return () => clearTimeout(timeout);
    }, [loading]);
    const messagesEndRef = useRef<HTMLDivElement>(null);

    // Fetch full profile details when active chat changes
    useEffect(() => {
        if (!activeChat) { setActiveChatProfile(null); return; }
        const fetchContactProfile = async () => {
            const { data } = await supabase
                .from('profiles')
                .select('bio, student_id, department, designation, employee_id, email')
                .eq('id', activeChat.id)
                .single();
            if (data) setActiveChatProfile(data);
        };
        fetchContactProfile();
    }, [activeChat?.id]);
    // EAGER LOAD: Sidebar Users
    useEffect(() => {
        if (!user?.id) return;

        const loadInitialChats = async () => {
            try {
                // Eagerly determine role (prioritize verified profile, fallback to metadata)
                const currentRole = profile?.role || user.user_metadata?.role;
                if (!currentRole) return;

                if (currentRole === 'mentee') {
                    // Try to get mentor info from global cache first
                    if (globalData.myMentor) {
                        const mentorChat: ChatUser = {
                            id: globalData.myMentor.id,
                            name: globalData.myMentor.name,
                            role: globalData.myMentor.role,
                            avatar: getInitials(globalData.myMentor.name),
                            isPinnedMentor: true
                        };
                        setChatUsers(prev => JSON.stringify(prev) === JSON.stringify([mentorChat]) ? prev : [mentorChat]);
                        setLoading(false);
                    }

                    // Background verify mentor assignment
                    const { data: menteeData } = await supabase
                        .from('mentees')
                        .select('assigned_mentor_id')
                        .eq('id', user.id)
                        .maybeSingle();

                    if (menteeData?.assigned_mentor_id) {
                        const { data: mentorProfile } = await supabase
                            .from('profiles')
                            .select('id, full_name, role, email')
                            .eq('id', menteeData.assigned_mentor_id)
                            .single();

                        if (mentorProfile) {
                            const name = mentorProfile.full_name || (mentorProfile.email ? mentorProfile.email.split('@')[0] : 'Mentor');
                            const freshMentor: ChatUser = {
                                id: mentorProfile.id,
                                name: name,
                                role: mentorProfile.role,
                                avatar: getInitials(name),
                                isPinnedMentor: true
                            };

                            // Reconciliation
                            setChatUsers(prev => JSON.stringify(prev) === JSON.stringify([freshMentor]) ? prev : [freshMentor]);
                        }
                    }
                } else if (currentRole === 'mentor') {
                    // Start with cache
                    if (globalData.myMentees?.length > 0) {
                        const cached = globalData.myMentees.map((m: any) => ({
                            id: m.profileId || m.id,
                            name: m.name,
                            role: 'mentee',
                            avatar: getInitials(m.name),
                            student_id: m.student_id
                        }));
                        setChatUsers(prev => JSON.stringify(prev) === JSON.stringify(cached) ? prev : cached);
                        setLoading(false);
                    }

                    // Background refresh
                    const { data: mRows } = await supabase
                        .from('mentees')
                        .select('profiles:profiles!fk_mentee_profile(id, full_name, student_id)')
                        .eq('assigned_mentor_id', user.id);

                    if (mRows) {
                        const freshMentees = mRows
                            .filter((m: any) => m.profiles)
                            .map((m: any) => ({
                                id: m.profiles.id,
                                name: m.profiles.full_name || 'Mentee',
                                role: 'mentee',
                                avatar: getInitials(m.profiles.full_name || 'Mentee'),
                                student_id: m.profiles.student_id
                            }));

                        // Reconciliation
                        setChatUsers(prev => JSON.stringify(prev) === JSON.stringify(freshMentees) ? prev : freshMentees);
                    }
                }
            } catch (error) {
                logger.error("MessagesPage", "Error loading chats", error);
            } finally {
                setLoading(false);
            }
        };

        loadInitialChats();
    }, [user?.id, profile?.role]);




    // Fetch Messages & Subscribe when Active Chat Changes
    useEffect(() => {
        if (!user?.id || !activeChat?.id) return;

        // Reset state and show loading
        setMessages([]);
        setMessagesLoading(true);

        const userId = user.id;
        const chatId = activeChat.id;
        let channel: any;
        let cancelled = false;

        const loadMessages = async () => {
            try {
                const { data, error } = await supabase
                    .from('chat_messages')
                    .select('*')
                    .or(`and(sender_id.eq.${userId},receiver_id.eq.${chatId}),and(sender_id.eq.${chatId},receiver_id.eq.${userId})`)
                    .order('created_at', { ascending: true });

                if (cancelled) return;

                if (error) {
                    logger.error("MessagesPage", "Load error", error);
                    return;
                }

                setMessages(data || []);
                // Scroll to bottom
                setTimeout(() => messagesEndRef.current?.scrollIntoView({ behavior: 'auto' }), 100);
            } catch (err) {
                logger.error("MessagesPage", "Fatal load error", err);
            } finally {
                if (!cancelled) setMessagesLoading(false);
            }
        };

        const setupSubscription = () => {
            const channelId = [userId, chatId].sort().join('_');
            
            channel = supabase
                .channel(`chat_${channelId}`)
                .on('postgres_changes', {
                    event: 'INSERT',
                    schema: 'public',
                    table: 'chat_messages'
                }, (payload: any) => {
                    if (cancelled) return;
                    const newMsg = payload.new as Message;
                    newMsg.status = 'sent'; // Incoming from Postgres is always 'sent'

                    // Reconciliation: Only add if relevant and not already in state
                    const isRelevant = 
                        (newMsg.sender_id === userId && newMsg.receiver_id === chatId) ||
                        (newMsg.sender_id === chatId && newMsg.receiver_id === userId);

                    if (isRelevant) {
                        setMessages((prev) => {
                            // 1. Precise Deduplication
                            if (newMsg.id && prev.some(m => m.id === newMsg.id)) return prev;
                            
                            // 2. Focused Replacement
                            const optIndex = prev.findIndex(m => 
                                m.status === 'sending' && 
                                m.content === newMsg.content &&
                                m.sender_id === newMsg.sender_id
                            );

                            if (optIndex !== -1) {
                                const next = [...prev];
                                const merged = {
                                    ...newMsg,
                                    status: 'sent' as const
                                };
                                next[optIndex] = merged;
                                return next;
                            }
                            
                            return [...prev, { ...newMsg, status: 'sent' as const }];
                        });
                    }
                })
                .subscribe();
        };

        loadMessages();
        setupSubscription();

        return () => {
            cancelled = true;
            if (channel) supabase.removeChannel(channel);
        };
    }, [user?.id, activeChat?.id]); // Stable dependencies

    // Handle Search
    const handleSearch = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!searchQuery.trim() || !user || !profile) return;

        // Try to find in existing chats first
        const localMatch = chatUsers.find(c =>
            c.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
            (c.student_id && c.student_id.toLowerCase().includes(searchQuery.toLowerCase()))
        );

        if (localMatch) {
            setActiveChat(localMatch);
            setSearchQuery("");
            return;
        }

        // If not found locally, search the database by Roll Number for global students
        try {
            // Both Mentees and Mentors can initiate a chat by searching a Roll Number
            const { data: searchResults } = await supabase
                .from('profiles')
                .select('id, full_name, role, student_id')
                .eq('role', 'mentee')
                .ilike('student_id', `%${searchQuery.trim()}%`)
                .neq('id', user.id)
                .limit(5);

            if (searchResults && searchResults.length > 0) {
                const newUsers = searchResults.map(p => ({
                    id: p.id,
                    name: p.full_name,
                    role: 'mentee',
                    avatar: p.full_name.substring(0, 2).toUpperCase(),
                    student_id: p.student_id
                }));

                setChatUsers(prev => {
                    const existingIds = new Set(prev.map(p => p.id));
                    const uniqueNew = newUsers.filter(n => !existingIds.has(n.id));
                    return [...uniqueNew, ...prev]; // Put new searched users at the top
                });

                // Auto-select the first search result
                setActiveChat(newUsers[0]);
                setSearchQuery("");
            } else {
                toast("No mentee found with that Roll Number.", "warning");
            }
        } catch (error) {
            logger.error("MessagesPage", "Search error", error);

        }
    };

    const handleSendMessage = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!newMessage.trim() || !user || !activeChat || !profile) return;

        const content = newMessage.trim();
        const optimisticId = `optimistic_${Date.now()}`;
        setNewMessage(""); // Input cleared immediately for UX

        // 1. SHOW INSTANTLY (Status: sending)
        const optimisticMsg: Message = {
            id: optimisticId,
            sender_id: user.id,
            receiver_id: activeChat.id,
            content,
            created_at: new Date().toISOString(),
            status: 'sending'
        };
        setMessages(prev => [...prev, optimisticMsg]);
        
        // 2. TRUE PERSISTENCE (Strict Await + Safety Race + Signal)
        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), 12000); // 12s hard signal

        try {
            const senderId = user.id;
            const receiverId = activeChat.id;
            console.log("MESSAGES_DEBUG: [DB_WRITE] Attempting insert", { 
                optimisticId, 
                senderId, 
                receiverId
            });
            
            // We use the AbortController signal to ensure the browser frees the socket
            const { data, error } = await supabase
                .from('chat_messages')
                .insert({
                    sender_id: senderId,
                    receiver_id: receiverId,
                    content: content
                })
                .select()
                .abortSignal(controller.signal)
                .single();

            if (error) {
                console.error("MESSAGES_DEBUG: [DB_WRITE] FAILED", error);
                throw error;
            }

            if (!data) throw new Error("No data returned from database.");

            // 3. UPGRADE TO SENT (Only on true DB confirmation)
            setMessages(prev => prev.map(m => 
                m.id === optimisticId ? { ...data, status: 'sent' as const } : m
            ));
            

        } catch (error: any) {
            console.error("MESSAGES_DEBUG: [DB_WRITE] FATAL EXCEPTION", error);
            const isTimeout = error.name === 'AbortError' || error.message?.includes('timeout');
            
            // Revert UI to error state
            setMessages(prev => prev.map(m => 
                m.id === optimisticId ? { ...m, status: 'error' as const } : m
            ));
            
            // Return text to input for retry
            setNewMessage(content);
            
            let errorHint = "Connection failed. Please check your internet.";
            if (isTimeout) {
                errorHint = "Database request timed out. The server might be busy.";
            } else if (error.message?.includes('policy')) {
                errorHint = "Security policy blocked this message. Please re-login.";
            } else if (error.message) {
                errorHint = error.message;
            }
            
            toast(errorHint, "error");
        } finally {
            clearTimeout(timeoutId);
        }
    };

    // Auto-scroll when messages change or length updates
    useEffect(() => {
        if (messages.length > 0) {
            messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
        }
    }, [messages.length, activeChat?.id]);



    // ZERO-LATENCY UI: Only block the whole page if we have NO identity info.
    const isBlocking = authLoading && !profile?.role && !user?.user_metadata?.role;

    if (isBlocking) {
        return (
            <div className="h-full w-full flex flex-col md:flex-row animate-in fade-in duration-300 overflow-hidden bg-white dark:bg-slate-950">
                {/* ===== Sidebar skeleton ΓÇö exact same widths as real sidebar ===== */}
                <div className="w-full md:w-80 lg:w-[400px] flex flex-col shrink-0 h-full border-r border-slate-200 dark:border-white/10 bg-white dark:bg-slate-950/50">
                    {/* "Messages" title */}
                    <div className="p-6 pb-2">
                        <div className="h-8 w-32 rounded-xl bg-slate-300 dark:bg-white/15 shimmer-skeleton" />
                    </div>
                    {/* Search bar ΓÇö same rounded-2xl style as real */}
                    <div className="px-6 mb-4">
                        <div className="h-11 w-full rounded-2xl bg-slate-100 dark:bg-white/8 border border-slate-200 dark:border-white/5 shimmer-skeleton" />
                    </div>
                    {/* Contact list ΓÇö 5 pills mirroring real items */}
                    <div className="flex-1 px-3 space-y-0.5">
                        {[58, 72, 45, 66, 80].map((w, i) => (
                            <div key={i} className="flex items-center gap-4 p-3.5 rounded-2xl">
                                <div className="w-11 h-11 rounded-xl bg-slate-200 dark:bg-white/12 shrink-0 shimmer-skeleton" />
                                <div className="flex-1 space-y-2">
                                    <div className="h-3.5 rounded-md bg-slate-200 dark:bg-white/12 shimmer-skeleton" style={{ width: `${w}%` }} />
                                    <div className="h-3 w-20 rounded-md bg-slate-100 dark:bg-white/6 shimmer-skeleton" />
                                </div>
                            </div>
                        ))}
                    </div>
                </div>

                {/* ===== Chat panel ΓÇö mirrors the "select a contact" empty state ===== */}
                <div className="flex-1 flex-col items-center justify-center p-8 text-center bg-white dark:bg-slate-950 hidden md:flex">
                    <div className="w-24 h-24 rounded-2xl bg-slate-100 dark:bg-white/5 flex items-center justify-center mb-6 shimmer-skeleton">
                        <div className="w-10 h-10 rounded-xl bg-slate-200 dark:bg-white/10 shimmer-skeleton" />
                    </div>
                    <div className="space-y-3 flex flex-col items-center">
                        <div className="h-6 w-44 rounded-xl bg-slate-200 dark:bg-white/12 shimmer-skeleton" />
                        <div className="h-4 w-64 rounded-lg bg-slate-100 dark:bg-white/6 shimmer-skeleton" />
                        <div className="h-4 w-52 rounded-lg bg-slate-100 dark:bg-white/6 shimmer-skeleton" />
                    </div>
                </div>
            </div>
        );
    }


    return (
        <div className="h-full w-full flex flex-col md:flex-row animate-in fade-in duration-500 overflow-hidden bg-white dark:bg-slate-950">
            {/* Sidebar - Chat List */}
            <div className={cn(
                "w-full md:w-80 lg:w-[400px] flex flex-col shrink-0 h-full border-r border-slate-200 dark:border-white/10 bg-white dark:bg-slate-950/50 backdrop-blur-md transition-all",
                showMobileThread ? "hidden md:flex" : "flex"
            )}>
                <div className="flex-1 flex flex-col h-full overflow-hidden">
                    <div className="p-6 pb-2">
                        <h2 className="text-2xl font-black text-slate-950 dark:text-white tracking-tight">Messages</h2>
                    </div>

                    <div className="px-6 mb-4 shrink-0 group">
                        <div className="relative">
                            <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 group-focus-within:text-primary transition-colors" />
                            <input
                                type="text"
                                placeholder={profile?.role === 'mentee' ? "Find your mentor..." : "Search mentees..."}
                                value={searchQuery}
                                onChange={(e) => setSearchQuery(e.target.value)}
                                className="w-full pl-11 pr-4 py-3 rounded-2xl bg-slate-100 dark:bg-slate-900/50 border border-transparent focus:border-primary/20 outline-none text-[15px] focus:ring-4 focus:ring-primary/5 transition-all"
                            />
                        </div>
                    </div>

                    <div className="flex-1 overflow-y-auto space-y-0.5 px-3 custom-scrollbar">
                        {filteredUsers.length === 0 ? (
                            <div className="text-center py-12 px-4">
                                <MessageSquare className="w-10 h-10 text-slate-200 dark:text-slate-800 mx-auto mb-3" />
                                <p className="font-bold text-slate-400 text-sm">
                                    {searchQuery ? "No results found" : "No conversations"}
                                </p>
                            </div>
                        ) : (
                            filteredUsers.map((chat) => (
                                <button
                                    key={chat.id}
                                    onClick={() => {
                                        setActiveChat(chat);
                                        setShowMobileThread(true);
                                    }}
                                    className={`w-full p-3.5 rounded-2xl flex items-center gap-4 transition-all ${activeChat?.id === chat.id ? 'bg-primary text-white shadow-lg shadow-primary/20' : 'hover:bg-slate-100 dark:hover:bg-white/5 text-slate-600 dark:text-slate-400'}`}
                                >
                                    <div className="relative shrink-0">
                                        <div className={`w-11 h-11 rounded-xl flex items-center justify-center font-black text-sm ${activeChat?.id === chat.id ? 'bg-white/20' : 'bg-slate-200 dark:bg-slate-800 text-slate-500'}`}>
                                            {chat.avatar}
                                        </div>
                                    </div>
                                    <div className="flex-1 text-left min-w-0">
                                        <div className="flex justify-between items-center mb-0.5">
                                            <span className="font-bold text-[15px] truncate">
                                                {chat.name}
                                            </span>
                                            {chat.isPinnedMentor && <span className={cn("text-[8px] px-1.5 py-0.5 rounded bg-amber-100 dark:bg-amber-500/20 text-amber-600 font-black uppercase tracking-wider", activeChat?.id === chat.id && "bg-white/20 text-white")}>Mentor</span>}
                                        </div>
                                        <p className={`text-xs truncate font-medium ${activeChat?.id === chat.id ? 'text-white/80' : 'text-slate-500'}`}>
                                            {chat.student_id ? chat.student_id : 'Tap to chat'}
                                        </p>
                                    </div>
                                </button>
                            ))
                        )}
                    </div>
                </div>
            </div>

            {/* Main Chat Window */}
            <div className={cn(
                "flex-1 flex flex-col overflow-hidden h-full relative bg-white dark:bg-slate-950",
                !showMobileThread ? "hidden md:flex" : "flex"
            )}>
                {activeChat ? (
                    <div className="relative flex-1 flex flex-col h-full overflow-hidden bg-slate-50 dark:bg-slate-950/20">
                        {/* Chat Header */}
                        <div className="p-3 sm:p-4 border-b border-slate-200 dark:border-white/5 flex items-center justify-between shrink-0 bg-white/90 dark:bg-slate-900/90 backdrop-blur-xl z-20 shadow-sm">
                            <div className="flex items-center gap-2.5 sm:gap-4 overflow-hidden">
                                {/* Back button */}
                                <button
                                    onClick={() => {
                                        setShowMobileThread(false);
                                        setActiveChat(null);
                                        setShowProfile(false);
                                    }}
                                    className="md:hidden p-1 px-1.5 -ml-1 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg transition-colors text-slate-500 hover:text-primary active:scale-90"
                                    title="Back to contacts"
                                >
                                    <ChevronLeft className="w-6 h-6" />
                                </button>
                                <div className="w-8 h-8 sm:w-10 sm:h-10 rounded-xl bg-primary text-white flex items-center justify-center font-black uppercase text-xs sm:text-[14px] shadow-lg shadow-primary/20 shrink-0 border-2 border-white/10">
                                    {activeChat.avatar}
                                </div>
                                <div className="min-w-0 flex flex-col justify-center">
                                    <h3 className="font-bold text-slate-900 dark:text-white text-[15px] sm:text-lg flex items-center gap-2 truncate leading-none mb-1">
                                        {activeChat.name}
                                    </h3>
                                    <span className="text-[9px] sm:text-xs text-slate-500 dark:text-slate-400 font-bold uppercase tracking-wider leading-none">
                                        {activeChat.isPinnedMentor || activeChat.role === 'mentor' ? 'Faculty Mentor' : 'Mentee'}
                                    </span>
                                </div>
                            </div>
                            <div className="flex items-center gap-1">
                                <button
                                    onClick={() => setShowProfile((p: any) => !p)}
                                    className={`p-2 rounded-xl transition-all ${showProfile
                                        ? 'bg-primary/10 text-primary'
                                        : 'hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-400'
                                        }`}
                                >
                                    <Info className="w-5 h-5" />
                                </button>
                            </div>
                        </div>

                        {/* Profile Panel */}
                        {showProfile && activeChatProfile && (
                            <div className="absolute inset-0 md:inset-auto md:right-0 md:top-0 h-full w-full md:w-80 z-40 flex flex-col transition-all animate-in slide-in-from-right duration-300">
                                <div className="h-full bg-white/95 dark:bg-slate-900/95 backdrop-blur-2xl border-l border-slate-200 dark:border-white/5 shadow-2xl flex flex-col rounded-none md:rounded-r-[40px] overflow-hidden">
                                    {/* Panel Header */}
                                    <div className="p-5 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between shrink-0">
                                        <span className="text-sm font-bold text-slate-700 dark:text-slate-200 uppercase tracking-widest">Profile</span>
                                        <button
                                            onClick={() => setShowProfile(false)}
                                            className="p-1.5 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-400 hover:text-slate-600 transition-colors"
                                        >
                                            <X className="w-4 h-4" />
                                        </button>
                                    </div>

                                    {/* Avatar + Name */}
                                    <div className="flex flex-col items-center pt-8 pb-6 px-6 border-b border-slate-100 dark:border-slate-800">
                                        <div className="w-20 h-20 rounded-2xl bg-gradient-to-br from-primary/20 to-blue-600/20 flex items-center justify-center text-primary font-black text-2xl shadow-lg border-2 border-primary/20 mb-4">
                                            {activeChat.avatar}
                                        </div>
                                        <h3 className="text-base font-bold text-slate-900 dark:text-white text-center leading-snug">
                                            {activeChat.name}
                                        </h3>
                                        <span className={`mt-2 text-[10px] font-black uppercase tracking-widest px-3 py-1 rounded-full ${activeChat.isPinnedMentor
                                            ? 'bg-amber-500/10 text-amber-600 border border-amber-500/20'
                                            : 'bg-primary/10 text-primary border border-primary/20'
                                            }`}>
                                            {activeChat.isPinnedMentor ? 'Faculty Mentor' : 'Mentee'}
                                        </span>
                                    </div>

                                    {/* Details Grid */}
                                    <div className="flex-1 overflow-y-auto px-5 py-5 space-y-4">
                                        {/* ID */}
                                        {(activeChatProfile.student_id || activeChatProfile.employee_id) && (
                                            <div>
                                                <p className="text-[10px] font-bold uppercase tracking-widest text-slate-400 dark:text-slate-500 mb-1">
                                                    {activeChat.isPinnedMentor ? 'Employee ID' : 'Roll Number'}
                                                </p>
                                                <p className="text-sm font-semibold text-slate-800 dark:text-slate-200 flex items-center gap-2">
                                                    {activeChat.isPinnedMentor
                                                        ? <Briefcase className="w-4 h-4 text-primary shrink-0" />
                                                        : <GraduationCap className="w-4 h-4 text-primary shrink-0" />
                                                    }
                                                    {activeChatProfile.student_id || activeChatProfile.employee_id}
                                                </p>
                                            </div>
                                        )}
                                        {/* Department */}
                                        {activeChatProfile.department && (
                                            <div>
                                                <p className="text-[10px] font-bold uppercase tracking-widest text-slate-400 dark:text-slate-500 mb-1">Department</p>
                                                <p className="text-sm font-semibold text-slate-800 dark:text-slate-200">{activeChatProfile.department}</p>
                                            </div>
                                        )}
                                        {/* Designation */}
                                        {activeChatProfile.designation && (
                                            <div>
                                                <p className="text-[10px] font-bold uppercase tracking-widest text-slate-400 dark:text-slate-500 mb-1">Designation</p>
                                                <p className="text-sm font-semibold text-slate-800 dark:text-slate-200">{activeChatProfile.designation}</p>
                                            </div>
                                        )}
                                        {/* Email */}
                                        {activeChatProfile.email && (
                                            <div>
                                                <p className="text-[10px] font-bold uppercase tracking-widest text-slate-400 dark:text-slate-500 mb-1">Email</p>
                                                <p className="text-sm font-semibold text-slate-800 dark:text-slate-200 break-all">{activeChatProfile.email}</p>
                                            </div>
                                        )}
                                        {/* Bio */}
                                        {activeChatProfile.bio && (
                                            <div>
                                                <p className="text-[10px] font-bold uppercase tracking-widest text-slate-400 dark:text-slate-500 mb-1">About</p>
                                                <p className="text-sm text-slate-600 dark:text-slate-400 leading-relaxed">{activeChatProfile.bio}</p>
                                            </div>
                                        )}
                                        {/* Fallback if nothing */}
                                        {!activeChatProfile.bio && !activeChatProfile.student_id && !activeChatProfile.employee_id && !activeChatProfile.department && !activeChatProfile.designation && (
                                            <p className="text-sm text-slate-400 text-center py-8 italic">No additional profile details available.</p>
                                        )}
                                    </div>
                                </div>
                            </div>
                        )}

                        {/* Message Area */}
                        <div className="flex-1 overflow-y-auto custom-scrollbar p-3 sm:p-8 pb-4 relative bg-white dark:bg-slate-950">
                            {/* Subtle background doodle effect - desktop only */}
                            <div className="hidden md:block absolute inset-0 opacity-[0.03] dark:opacity-[0.02] pointer-events-none bg-[radial-gradient(#000_1px,transparent_1px)] [background-size:20px_20px]" />

                            <div className="flex flex-col gap-4 relative z-10">
                                {messagesLoading ? (
                                    <div className="flex flex-col gap-4 py-6 px-2">
                                        {[70, 45, 85, 55, 75].map((w, i) => (
                                            <div key={i} className={`flex ${i % 2 === 0 ? 'justify-end' : 'justify-start'}`}>
                                                <div
                                                    className="h-10 rounded-[22px] bg-slate-100 dark:bg-slate-800 shimmer-skeleton"
                                                    style={{ width: `${w}%`, maxWidth: '70%' }}
                                                />
                                            </div>
                                        ))}
                                    </div>
                                ) : messages.length === 0 ? (
                                    <div className="text-center text-slate-400 text-sm italic py-10">
                                        Send a message to start the conversation.
                                    </div>
                                ) : (
                                    messages.map((msg, idx) => {
                                        const isMine = msg.sender_id === user?.id;
                                        const msgDate = new Date(msg.created_at);
                                        const timeStr = msgDate.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });

                                        const prevMsg = idx > 0 ? messages[idx - 1] : null;
                                        const prevDate = prevMsg ? new Date(prevMsg.created_at) : null;
                                        const showDateSeparator = !prevDate || prevDate.toDateString() !== msgDate.toDateString();

                                        let dateLabel = "";
                                        if (showDateSeparator) {
                                            const today = new Date();
                                            const yesterday = new Date();
                                            yesterday.setDate(today.getDate() - 1);
                                            dateLabel = msgDate.toDateString() === today.toDateString() ? "Today" :
                                                msgDate.toDateString() === yesterday.toDateString() ? "Yesterday" :
                                                    msgDate.toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric' });
                                        }

                                        return (
                                            <React.Fragment key={msg.id || idx}>
                                                {showDateSeparator && (
                                                    <div className="flex justify-center my-6">
                                                        <span className="px-4 py-1.5 bg-slate-100 dark:bg-slate-800/60 text-slate-500 dark:text-slate-400 text-[11px] font-semibold rounded-full select-none">
                                                            {dateLabel}
                                                        </span>
                                                    </div>
                                                )}
                                                <div className={cn("flex flex-col max-w-[85%] sm:max-w-[70%]", isMine ? "self-end items-end" : "self-start items-start")}>
                                                    <motion.div
                                                        initial={{ opacity: 0, scale: 0.95, y: 5 }}
                                                        animate={{ opacity: 1, scale: 1, y: 0 }}
                                                        className={cn(
                                                            "relative px-4 py-2.5 shadow-sm transition-all group",
                                                            isMine
                                                                ? cn(
                                                                    "bg-gradient-to-br from-primary to-blue-600 text-white rounded-[22px] rounded-tr-none shadow-lg shadow-primary/10",
                                                                    msg.status === 'error' && "from-red-500 to-red-600",
                                                                    msg.status === 'sending' && "opacity-80"
                                                                  )
                                                                : "bg-white dark:bg-slate-900 text-slate-800 dark:text-slate-100 rounded-[22px] rounded-tl-none border border-slate-200/50 dark:border-white/5"
                                                        )}
                                                    >
                                                        <p className="text-[15px] leading-relaxed whitespace-pre-wrap font-medium">{msg.content}</p>
                                                        <div className={cn("flex items-center gap-1 mt-1 justify-end opacity-60")}>
                                                            <span className="text-[9px] font-bold tracking-tighter">
                                                                {timeStr}
                                                            </span>
                                                            {isMine && (
                                                                <div className="flex items-center gap-1">
                                                                    {msg.status === 'sending' && <div className="w-2.5 h-2.5 border-2 border-white/30 border-t-white rounded-full animate-spin" />}
                                                                    {msg.status === 'sent' && <CheckCheck className="w-3 h-3" />}
                                                                    {msg.status === 'error' && <X className="w-3 h-3 text-white" />}
                                                                </div>
                                                            )}
                                                        </div>
                                                    </motion.div>
                                                </div>
                                            </React.Fragment>
                                        );
                                    })
                                )}
                                <div ref={messagesEndRef} />
                            </div>
                        </div>

                        {/* Message Input - Floating Capsule */}
                        <div className="p-3 sm:p-6 pb-4 md:pb-6 shrink-0 z-20 relative bg-white/80 dark:bg-slate-950/80 backdrop-blur-xl border-t border-slate-200/50 dark:border-white/10">
                            <form onSubmit={handleSendMessage} className="relative flex items-center gap-2 sm:gap-3">
                                <input
                                    value={newMessage}
                                    onChange={(e: any) => setNewMessage(e.target.value)}
                                    onKeyDown={(e) => {
                                        if (e.key === 'Enter' && !e.shiftKey) {
                                            e.preventDefault();
                                            if (newMessage.trim()) handleSendMessage(e as any);
                                        }
                                    }}
                                    placeholder="Type a message..."
                                    className="flex-1 px-5 py-3.5 rounded-2xl bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-white/5 focus:ring-2 focus:ring-primary/20 outline-none text-[15px] text-slate-800 dark:text-slate-200 placeholder:text-slate-400/70 transition-all"
                                />
                                <button
                                    disabled={!newMessage.trim()}
                                    type="submit"
                                    className="w-12 h-12 bg-primary text-white rounded-2xl shadow-lg shadow-primary/20 hover:bg-blue-600 active:scale-90 transition-all flex items-center justify-center disabled:opacity-50 shrink-0"
                                >
                                    <Send className="w-5 h-5" />
                                </button>
                            </form>
                        </div>

                    </div>
                ) : (
                    <div className="flex-1 flex flex-col items-center justify-center p-8 text-center bg-white dark:bg-slate-950/20">
                        <div className="w-24 h-24 bg-gradient-to-br from-primary/5 to-blue-600/5 dark:from-primary/10 dark:to-blue-600/10 rounded-2xl flex items-center justify-center mb-6">
                            <MessageSquare className="w-10 h-10 text-primary/40" />
                        </div>
                        <h3 className="text-2xl font-black text-slate-800 dark:text-white mb-2 uppercase tracking-tight">Your Messages</h3>
                        <p className="text-slate-500 dark:text-slate-400 text-base max-w-sm leading-relaxed font-medium">
                            Select a contact from the sidebar or search a roll number to start chatting securely.
                        </p>
                    </div>
                )}
            </div>
        </div>
    );
}

/**
 * @file dashboard/page.tsx
 * @description Main overview dashboard for authenticated users.
 *
 * Displays real-time stats, upcoming sessions, recent activity, and
 * quick-access cards. Renders different content for mentors vs mentees.
 * Statistics are fetched from `sessions`, `assignments`, and `mentees` tables.
 */

"use client";

import React from "react";
import { motion } from "framer-motion";
import { CONFIG } from "@/lib/config";
import {
    Users,
    Calendar,
    Clock,
    CheckCircle2,
    ArrowUpRight
} from "lucide-react";
import { useRouter } from "next/navigation";
import { supabase } from "@/lib/supabase";
import { useEffect, useState } from "react";
import { useAuth } from "@/contexts/AuthContext";
import { formatDate, getInitials } from "@/lib/date-utils";
import { useToast } from "@/components/Toast";
import { logger } from "@/lib/logger";
import { MentorDashboard } from "./components/MentorDashboard";
import { MenteeDashboard } from "./components/MenteeDashboard";

export interface DashboardStats {
    activeMentees: number;
    totalSessions: number;
    hoursGuided: number;
    completionRate: number;
}

export interface DashboardSession {
    id: string;
    mentor_id: string;
    mentee_id: string;
    status: string;
    scheduled_at: string;
    duration_minutes?: number;
    meeting_link?: string;
    topic?: string;
    title?: string;
    mentees?: {
        profiles: {
            full_name: string;
        };
    };
    mentee?: {
        full_name: string;
    };
}

export interface DashboardMentee {
    id: string;
    name: string;
    initials: string;
    progress: number;
}

export interface DashboardActivity {
    id: string;
    text: string;
    bold: string;
    type: 'task' | 'session';
    time: string;
}

interface LoadingStates {
    stats: boolean;
    sessions: boolean;
    mentees: boolean;
    activity: boolean;
    requests: boolean;
    auth: boolean;
}

export default function DashboardPage() {
    const router = useRouter();
    const { user, profile, loading: authLoading, globalData, updateGlobalData } = useAuth();
    const { toast } = useToast();

    const [stats, setStats] = useState<DashboardStats>({
        activeMentees: 0,
        totalSessions: 0,
        hoursGuided: 0,
        completionRate: 0,
    });
    const [upcomingSessions, setUpcomingSessions] = useState<DashboardSession[]>([]);
    const [menteeProgress, setMenteeProgress] = useState({ 
        mentorName: 'Unassigned Mentor', 
        nextSession: 'None Scheduled', 
        taskProgress: 0,
        total_sessions_attended: 0,
        mentor_id: null as string | null
    });

    const [loadingStates, setLoadingStates] = useState<LoadingStates>({
        stats: true,
        sessions: true,
        mentees: true,
        activity: true,
        requests: true,
        auth: true,
    });

    // Failsafe: max 10 seconds ΓÇö matches AuthContext timeout
    useEffect(() => {
        if (!loadingStates.auth) return;
        const timeout = setTimeout(() => {
            logger.warn("DashboardPage", "Failsafe: Auth resolution took too long, forcing resolution.");
            setLoadingStates(prev => ({ ...prev, auth: false }));
        }, CONFIG.TIMEOUTS.AUTH_RESOLUTION);
        return () => clearTimeout(timeout);
    }, [loadingStates.auth]);

    const [activeMentees, setActiveMentees] = useState<DashboardMentee[]>((globalData.mentees as DashboardMentee[]) || []);
    const [recentActivity, setRecentActivity] = useState<DashboardActivity[]>([]);

    // Determine initial stats from global cache if available
    useEffect(() => {
        if (globalData.mentees.length > 0 && profile?.role === 'mentor') {
            setActiveMentees(globalData.mentees as DashboardMentee[]);
            setLoadingStates(prev => ({ ...prev, mentees: false }));
        }
    }, [globalData.mentees, profile?.role]);

    // State for pending mentor requests (for mentees)
    const [pendingRequests, setPendingRequests] = useState<any[]>([]);
    const [rejectionReason, setRejectionReason] = useState("");
    const [showRejectionModal, setShowRejectionModal] = useState(false);
    const [selectedRequest, setSelectedRequest] = useState<any>(null);
    const [isProcessingRequest, setIsProcessingRequest] = useState(false);
    const [resolutionAttempt, setResolutionAttempt] = useState(0);
    const [refreshTrigger, setRefreshTrigger] = useState(0);
    const [isStuck, setIsStuck] = useState(false);
    const [mounted, setMounted] = useState(false);

    useEffect(() => {
        setMounted(true);
    }, []);

    // Track if we are stuck in "Resolving Identity"
    useEffect(() => {
        if (!authLoading && !profile?.role && !user?.user_metadata?.role) {
            const timer = setTimeout(() => setIsStuck(true), 5000);
            return () => clearTimeout(timer);
        } else {
            setIsStuck(false);
        }
    }, [authLoading, profile?.role, user?.user_metadata?.role, resolutionAttempt]);

    // Fetch dashboard data
    useEffect(() => {
        async function fetchDashboardData() {
            // EAGER FETCHING: Use user.id from session even if profile isn't verified yet
            const userId = profile?.id || user?.id;

            if (!userId) {
                // Only block if we truly have no identity
                if (!authLoading) setLoadingStates(prev => ({ ...prev, auth: false }));
                return;
            }

            try {
                // Determine effective role from profile (preferred) or metadata/localStorage fallback
                let effectiveRole = profile?.role || (user?.user_metadata?.role as string);
                if (!effectiveRole && typeof window !== 'undefined') {
                    const cachedProfile = localStorage.getItem(`nexus_profile_${userId}`);
                    if (cachedProfile) effectiveRole = JSON.parse(cachedProfile).role;
                }

                // SECURITY HARDENING
                if (!effectiveRole) {
                    setLoadingStates(prev => ({ ...prev, auth: false }));
                    return;
                }

                // ZERO-LATENCY STRATEGY:
                // If we have cached data, resolve the primary "blocking" loading state immediately.
                if (globalData.mentees.length > 0) setLoadingStates(prev => ({ ...prev, mentees: false }));
                if (upcomingSessions.length > 0) setLoadingStates(prev => ({ ...prev, sessions: false }));
                if (stats.totalSessions > 0) setLoadingStates(prev => ({ ...prev, stats: false }));

                setLoadingStates(prev => ({ ...prev, auth: false })); // Auth resolved, now fetching specific data

                if (effectiveRole === 'mentor') {
                    // ... (rest of mentor fetch logic)
                    // 1. Fetch mentor stats and sessions in parallel
                    const [
                        { data: menteesWithProfiles },
                        { data: sessions },
                        { data: upcoming },
                        { data: assignments }
                    ] = await Promise.all([
                        supabase.from('mentees')
                            .select('id, profiles:profiles!fk_mentee_profile(id, full_name, role), career_goals')
                            .eq('assigned_mentor_id', userId),
                        supabase.from('sessions')
                            .select('*')
                            .eq('mentor_id', userId),
                        supabase.from('sessions')
                            .select('*, mentee:profiles!mentee_id(full_name)')
                            .eq('mentor_id', userId)
                            .eq('status', 'scheduled')
                            .gte('scheduled_at', new Date().toISOString())
                            .order('scheduled_at', { ascending: true })
                            .limit(5),
                        supabase.from('assignments')
                            .select('id, status, created_at, title, mentee_id')
                            .eq('mentor_id', userId)
                    ]);

                    const completedCount = sessions?.filter(s => s.status === 'completed').length || 0;
                    const totalCount = sessions?.length || 1;

                    setStats({
                        activeMentees: menteesWithProfiles?.length || 0,
                        totalSessions: sessions?.length || 0,
                        hoursGuided: Math.round((sessions?.reduce((acc, s) => acc + (s.duration_minutes || 0), 0) || 0) / 60),
                        completionRate: Math.round((completedCount / totalCount) * 100),
                    });

                    // 2. Synthesize mentee details and activity feed
                    if (menteesWithProfiles && menteesWithProfiles.length > 0) {
                        const menteeStats = menteesWithProfiles.map((m: any) => {
                            const mAssignments = assignments?.filter(a => a.mentee_id === m.id) || [];
                            const completed = mAssignments.filter((a: any) => ['submitted', 'reviewed'].includes(a.status)).length;
                            const progress = mAssignments.length > 0 ? Math.round((completed / mAssignments.length) * 100) : 0;
                            const p = m.profiles as any;
                            const name = p?.full_name || (p?.email ? p.email.split('@')[0] : 'Mentee');
                            return {
                                id: m.id,
                                name,
                                initials: getInitials(name),
                                progress: progress
                            };
                        });
                        setActiveMentees(menteeStats);

                        // Update global cache
                        if (menteeStats.length > 0) {
                            updateGlobalData('mentees', menteeStats);
                        }

                        // 3. Synthesize Activity Feed
                        const activities: DashboardActivity[] = [];
                        if (assignments && assignments.length > 0) {
                            const sortedAssignments = [...assignments].sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime());
                            sortedAssignments.slice(0, 3).forEach(a => {
                                const mName = (menteesWithProfiles.find(m => m.id === a.mentee_id)?.profiles as any)?.full_name || 'Mentee';
                                activities.push({
                                    id: `task-${a.mentee_id}-${a.created_at}`,
                                    text: `You assigned a new task "${a.title}" to `,
                                    bold: mName,
                                    type: 'task',
                                    time: a.created_at
                                });
                            });
                        }
                        if (sessions) {
                            sessions.filter(s => s.status === 'completed').sort((a, b) => new Date(b.scheduled_at).getTime() - new Date(a.scheduled_at).getTime()).slice(0, 2).forEach(s => {
                                const mName = (menteesWithProfiles.find((m: any) => m.id === s.mentee_id)?.profiles as any)?.full_name || 'Mentee';
                                activities.push({
                                    id: `session-${s.id}`,
                                    text: `Session completed with `,
                                    bold: mName,
                                    type: 'session',
                                    time: s.scheduled_at
                                });
                            });
                        }
                        setRecentActivity(activities.sort((a, b) => new Date(b.time).getTime() - new Date(a.time).getTime()).slice(0, 4));
                    }

                    // Map upcoming sessions to nested structure for MentorDashboard compatibility
                    setUpcomingSessions(upcoming?.map((s: any) => ({
                        ...s,
                        mentees: { profiles: s.mentee }
                    })) || []);

                    updateGlobalData('dashboard', []);

                } else if (effectiveRole === 'mentee') {
                    logger.info("DashboardPage", `Mentees fetch: Role=mentee, UserId=${userId}`);

                    const [
                        { data: requests, error: requestsError },
                        { data: menteeRecordRaw },
                        { data: sessions },
                        { data: assignments }
                    ] = await Promise.all([
                        supabase.from('mentor_requests').select('*, mentor:profiles!mentor_id(full_name, expertise)').eq('mentee_id', userId).ilike('status', 'pending'),
                        supabase.from('mentees').select('assigned_mentor_id, total_sessions_attended').eq('id', userId).maybeSingle(),
                        supabase.from('sessions').select('*').eq('mentee_id', userId).eq('status', 'scheduled').gte('scheduled_at', new Date().toISOString()).order('scheduled_at', { ascending: true }).limit(1),
                        supabase.from('assignments').select('status').eq('mentee_id', userId)
                    ]);

                    const menteeRecord = menteeRecordRaw as any;
                    if (menteeRecord?.assigned_mentor_id) {
                        try {
                            const { data: mentorProfile } = await supabase
                                .from('profiles')
                                .select('full_name')
                                .eq('id', menteeRecord.assigned_mentor_id)
                                .single();
                            if (mentorProfile) {
                                menteeRecord.mentor = mentorProfile;
                            }
                        } catch (e) {
                            logger.warn("DashboardPage", "Mentor profile fetch failed", e);
                        }
                    }

                    if (requestsError) {
                        logger.error("DashboardPage", "Error fetching requests", requestsError);
                    }

                    let effectiveRequests = requests || [];

                    // RESCUE FETCH: If no requests found by ID, try by EMAIL (in case of identity fragmentation)
                    if (effectiveRequests.length === 0 && user?.email) {
                        logger.warn("DashboardPage", `No requests for ID ${userId}, trying rescue fetch by email ${user.email}`);
                        const { data: rescueRequests, error: rescueError } = await supabase
                            .from('mentor_requests')
                            .select('*, mentor:profiles!mentor_id(full_name, expertise), mentee:profiles!mentee_id!inner(email)')
                            .eq('mentee.email', user.email)
                            .ilike('status', 'pending');

                        if (rescueError) {
                            logger.error("DashboardPage", "Rescue fetch error", rescueError);
                        }

                        if (rescueRequests && rescueRequests.length > 0) {
                            logger.info("DashboardPage", `Rescue found ${rescueRequests.length} requests by email.`);
                            effectiveRequests = rescueRequests;
                        }
                    }

                    logger.info("DashboardPage", `Mentee Data Resolved: RequestsCount=${effectiveRequests.length}, Mentor=${(menteeRecord as any)?.mentor?.full_name || 'None'}`);

                    const mentorName = (menteeRecord as any)?.mentor?.full_name || 'Unassigned';

                    setPendingRequests(effectiveRequests);

                    let nextSessionText = 'No upcoming sessions';
                    if (sessions && sessions.length > 0) {
                        nextSessionText = formatDate(sessions[0].scheduled_at);
                    }

                    let completionRatio = 0;
                    if (assignments && assignments.length > 0) {
                        const completed = assignments.filter((a: any) => ['submitted', 'reviewed'].includes(a.status)).length;
                        completionRatio = Math.round((completed / assignments.length) * 100);
                    }

                    setMenteeProgress({
                        mentorName: mentorName,
                        nextSession: nextSessionText,
                        taskProgress: completionRatio,
                        total_sessions_attended: menteeRecord?.total_sessions_attended || 0,
                        mentor_id: menteeRecord?.assigned_mentor_id || null
                    });
                }
            } catch (error) {
                logger.error("DashboardPage", "Error fetching dashboard data", error);
            } finally {
                setLoadingStates(prev => ({ ...prev, auth: false, stats: false, sessions: false, mentees: false, activity: false, requests: false }));
            }
        }

        fetchDashboardData();

        // ≡ƒƒó FULL-APP REAL-TIME SYNC
        const userId = profile?.id || user?.id;
        if (!userId) return;

        logger.info("DashboardPage", "Setting up global real-time listeners...");
        
        const channel = supabase
            .channel('dashboard-realtime')
            .on(
                'postgres_changes',
                { event: '*', schema: 'public', table: 'mentor_requests', filter: `mentee_id=eq.${userId}` },
                () => {
                    logger.debug("DashboardPage", "Mentor request changed, refreshing...");
                    fetchDashboardData();
                }
            )
            .on(
                'postgres_changes',
                { event: '*', schema: 'public', table: 'sessions' }, // Filter by mentor_id/mentee_id in production if possible
                () => {
                    logger.debug("DashboardPage", "Sessions changed, refreshing stats...");
                    fetchDashboardData();
                }
            )
            .on(
                'postgres_changes',
                { event: '*', schema: 'public', table: 'assignments' },
                () => {
                    logger.debug("DashboardPage", "Assignments changed, refreshing stats...");
                    fetchDashboardData();
                }
            )
            .subscribe();

        return () => {
            supabase.removeChannel(channel);
        };
    }, [profile, refreshTrigger]);

    const handleAcceptRequest = async (request: any) => {
        if (!request || !profile) return;
        setIsProcessingRequest(true);
        try {
            const acceptPromise = (async () => {
                // 1. Update request status
                logger.info("DashboardPage", "Step 1: Updating request status...");
                const { error: reqError } = await supabase
                    .from('mentor_requests')
                    .update({ status: 'accepted', updated_at: new Date().toISOString() })
                    .eq('id', request.id);

                if (reqError) {
                    logger.error("DashboardPage", "Failed to update request status", reqError);
                    throw new Error(`Request update failed: ${reqError.message}`);
                }
                logger.info("DashboardPage", "Step 1 successful. Server-side triggers will handle account provisioning.");

                // Step 2 & 3: Mentor record & Mentee assignment are now handled by 
                // the 'on_mentor_request_accepted' trigger in Supabase.


                // 3. Automatically decline other pending requests (background)
                const otherRequests = pendingRequests.filter(r => r.id !== request.id);
                if (otherRequests.length > 0) {
                    supabase
                        .from('mentor_requests')
                        .update({
                            status: 'rejected',
                            rejection_reason: 'Accepted another mentor request.',
                            updated_at: new Date().toISOString()
                        })
                        .in('id', otherRequests.map(r => r.id))
                        .then(() => { });
                }

                // 4. Notify the mentor: Handled by 'on_mentor_request_accepted' trigger.
            })();


            const timeoutPromise = new Promise((_, reject) =>
                setTimeout(() => reject(new Error('TIMEOUT')), 8000)
            );

            await Promise.race([acceptPromise, timeoutPromise]);

            toast(`You are now connected with ${request.mentor?.full_name}!`, "success");
            setPendingRequests(prev => prev.filter(r => r.id !== request.id));

            // Re-fetch everything after a short delay
            setTimeout(() => window.location.reload(), 1000);

        } catch (err: any) {
            logger.error("DashboardPage", "Accept request failed", err);
            if (err.message === 'TIMEOUT') {
                toast("Connection is taking too long. Please refresh.", "error");
            } else {
                toast("Failed to accept request. Please try again.", "error");
            }
        } finally {
            setIsProcessingRequest(false);
        }
    };

    const handleRejectRequest = async () => {
        if (!selectedRequest || !rejectionReason.trim()) return;
        setIsProcessingRequest(true);
        try {
            await supabase
                .from('mentor_requests')
                .update({
                    status: 'rejected',
                    rejection_reason: rejectionReason,
                    updated_at: new Date().toISOString()
                })
                .eq('id', selectedRequest.id);

            toast("Request declined.", "info");

            // 2. Notify the mentor
            await supabase.from('notifications').insert({
                recipient_id: selectedRequest.mentor_id,
                type: 'request',
                title: 'Connection Declined',
                content: `${profile?.full_name || 'A mentee'} declined your request. Reason: ${rejectionReason}`,
                link: '/dashboard',
                is_read: false
            });

            setPendingRequests(prev => prev.filter(r => r.id !== selectedRequest.id));
            setSelectedRequest(null);
            setShowRejectionModal(false);
        } catch (err: any) {
            toast("Failed to decline request.", "error");
        } finally {
            setIsProcessingRequest(false);
        }
    };

    // ZERO-LATENCY UI: Only show blocking skeleton if we have literally NO data to show
    const effectiveRole = profile?.role ||
        (user?.user_metadata?.role as string) ||
        (typeof window !== 'undefined' ? JSON.parse(localStorage.getItem(`nexus_profile_${user?.id}`) || '{}').role : null);

    const hasVisibleContent = effectiveRole === 'mentor'
        ? (activeMentees.length > 0 || stats.totalSessions > 0)
        : effectiveRole === 'mentee'
            ? (menteeProgress.mentorName !== 'Unassigned Mentor' || pendingRequests.length > 0)
            : false;

    const isBlocking = !mounted || (authLoading && !effectiveRole);

    // SECURITY BRANCH: If we have no role yet but aren't blocking, we must show a neutral "Resolving" state
    // rather than defaulting to the Mentor view. 
    if (!isBlocking && !effectiveRole) {
        return (
            <div className="min-h-screen flex items-center justify-center bg-slate-50 dark:bg-slate-950 p-4">
                <div className="text-center space-y-8 max-w-sm animate-in fade-in zoom-in duration-500">
                    {/* BUG-4 FIX: Spinner rings need a relative parent so their absolute positioning works correctly */}
                    <div className="relative inline-block w-20 h-20 mx-auto">
                        <div className="absolute inset-2 border-2 border-primary/20 rounded-full" />
                        <div className="absolute inset-0 border-4 border-primary rounded-full border-t-transparent animate-spin" />
                        <div className="absolute inset-0 flex items-center justify-center">
                            <Clock className="w-8 h-8 text-primary/40" />
                        </div>
                    </div>

                    <div className="space-y-3">
                        <h2 className="text-2xl font-black text-slate-900 dark:text-white tracking-tight">Resolving Identity</h2>
                        <p className="text-slate-500 dark:text-slate-400 text-sm font-medium leading-relaxed">
                            {isStuck ? "This is taking longer than expected. Most likely your profile is still being synchronized." : "Please wait while we secure your session and prepare your dashboard..."}
                        </p>
                    </div>

                    {isStuck && (
                        <motion.div
                            initial={{ opacity: 0, y: 10 }}
                            animate={{ opacity: 1, y: 0 }}
                            className="space-y-4 pt-4 border-t border-slate-200 dark:border-slate-800"
                        >
                            <button
                                onClick={() => {
                                    setResolutionAttempt(prev => prev + 1);
                                    window.location.reload();
                                }}
                                className="w-full py-4 rounded-2xl bg-primary text-white font-bold shadow-lg shadow-primary/20 hover:bg-blue-700 transition-all"
                            >
                                Refresh Dashboard
                            </button>
                            <p className="text-[10px] font-black uppercase tracking-widest text-slate-400">Or</p>
                            <button
                                onClick={() => {
                                    localStorage.clear();
                                    supabase.auth.signOut().then(() => window.location.replace("/"));
                                }}
                                className="text-sm font-bold text-slate-500 hover:text-slate-800 dark:hover:text-slate-200 transition-colors"
                            >
                                Sign Out &amp; Try Again
                            </button>
                        </motion.div>
                    )}
                </div>
            </div>
        );
    }

    if (isBlocking) {
        // ... (existing loading skeleton remains same)
        return (
            <div className="space-y-10 animate-in fade-in duration-500 w-full pb-12">
                <div className="space-y-3">
                    <div className="h-10 w-72 bg-slate-200 dark:bg-slate-800 rounded-2xl shimmer-skeleton"></div>
                    <div className="h-5 w-full max-w-sm bg-slate-100 dark:bg-slate-800/60 rounded-xl shimmer-skeleton"></div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                    {[1, 2, 3, 4].map(i => (
                        <div key={i} className="h-32 bg-white/40 dark:bg-slate-900/40 rounded-2xl border border-slate-200/40 dark:border-slate-800/40 shimmer-skeleton"></div>
                    ))}
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                    <div className="lg:col-span-2 space-y-8">
                        <div className="h-7 w-48 bg-slate-200/60 dark:bg-slate-800/60 rounded-xl shimmer-skeleton"></div>
                        <div className="space-y-4">
                            {[1, 2, 3].map(i => (
                                <div key={i} className="h-24 bg-white/40 dark:bg-slate-900/40 rounded-2xl border border-slate-200/40 dark:border-slate-800/40 shimmer-skeleton"></div>
                            ))}
                        </div>
                    </div>
                    <div className="space-y-8">
                        <div className="h-7 w-32 bg-slate-200/60 dark:bg-slate-800/60 rounded-xl shimmer-skeleton"></div>
                        <div className="h-[420px] bg-white/40 dark:bg-slate-900/40 rounded-2xl border border-slate-200/40 dark:border-slate-800/40 shimmer-skeleton"></div>
                    </div>
                </div>
            </div>
        );
    }

    // Role-based Layouts
    if (profile?.role === 'mentee') {
        return (
            <MenteeDashboard
                profile={profile}
                user={user}
                pendingRequests={pendingRequests}
                menteeProgress={menteeProgress}
                dataLoading={loadingStates.auth}
                handleAcceptRequest={handleAcceptRequest}
                handleRejectRequest={handleRejectRequest}
                setShowRejectionModal={setShowRejectionModal}
                setSelectedRequest={setSelectedRequest}
                rejectionReason={rejectionReason}
                setRejectionReason={setRejectionReason}
                showRejectionModal={showRejectionModal}
                selectedRequest={selectedRequest}
                isProcessingRequest={isProcessingRequest}
                toast={toast}
            />
        );
    }

    if (effectiveRole === 'mentor') {
        return (
            <MentorDashboard
                profile={profile}
                user={user}
                stats={stats}
                upcomingSessions={upcomingSessions}
                activeMentees={activeMentees}
                recentActivity={recentActivity}
                dataLoading={loadingStates.auth}
                router={router}
                statsConfig={[
                    { key: "activeMentees", label: "Active Mentees", icon: Users, color: "text-blue-600", bg: "bg-blue-100" },
                    { key: "totalSessions", label: "Total Sessions", icon: Calendar, color: "text-purple-600", bg: "bg-purple-100" },
                    { key: "completionRate", label: "Completion Rate", icon: CheckCircle2, color: "text-emerald-600", bg: "bg-emerald-100" },
                ]}
            />
        );
    }


    // FINAL FALLBACK: If we're not mentor and not mentee (or if somehow we reached here),
    // show a safe descriptive message or the student view.
    return (
        <div className="h-[60vh] flex flex-col items-center justify-center space-y-4 animate-in fade-in duration-700">
            <div className="w-16 h-16 border-4 border-slate-200 border-t-primary rounded-full animate-spin" />
            <div className="text-center">
                <h3 className="text-lg font-bold text-slate-900 dark:text-white">Connecting...</h3>
                <p className="text-sm text-slate-500 dark:text-slate-400">Finalizing your dashboard settings...</p>
            </div>
        </div>
    );
}

/**
 * @file dashboard/sessions/page.tsx
 * @description Session scheduling and management page.
 *
 * Mentors can schedule new sessions, view upcoming meetings, and cancel sessions.
 * Mentees can view upcoming sessions, join via meeting link, and see past history.
 * Session data is stored in the Supabase `sessions` table.
 */

"use client";

import React, { useState, useEffect } from "react";
import { motion } from "framer-motion";
import { Calendar as CalendarIcon, Clock, Video, Plus, CheckCircle2, AlertCircle, ChevronRight, X, User, Users, Link as LinkIcon, ExternalLink } from "lucide-react";
import { supabase } from "@/lib/supabase";
import { useAuth } from "@/contexts/AuthContext";
import { formatDate, groupItemsByDate } from "@/lib/date-utils";
import { useToast } from "@/components/Toast";
import { logger } from "@/lib/logger";
import { downloadCSV } from "@/lib/csv-export";
import type { FormattedSession, MenteeOption, NewSessionForm } from "@/types/app";

export default function SessionsPage() {
    const { user, profile, loading: authLoading, globalData, updateGlobalData } = useAuth();
    const { toast, confirm } = useToast();

    const [sessions, setSessions] = useState<any[]>(() =>
        globalData.sessions?.length > 0 ? (globalData.sessions as any[]) : []
    );
    const [loading, setLoading] = useState(() =>
        !(globalData.sessions?.length > 0)
    );
    const [refreshTrigger, setRefreshTrigger] = useState(0);

    // Failsafe: max 10 seconds ΓÇö matches AuthContext timeout
    useEffect(() => {
        if (!loading) return;
        const timeout = setTimeout(() => {
            logger.warn("SessionsPage", "Failsafe: Loading took too long, forcing resolution.");
            setLoading(false);
        }, 10000);
        return () => clearTimeout(timeout);
    }, [loading]);

    const [isModalOpen, setIsModalOpen] = useState(false);
    const [myMentees, setMyMentees] = useState<any[]>([]);
    const [menteesLoading, setMenteesLoading] = useState(false);
    const defaultSession = {
        title: "",
        mentee_id: "",
        scheduled_at: "",
        duration_minutes: 60,
        session_type: "one-on-one",
        meeting_link: ""
    };
    const [newSession, setNewSession] = useState(defaultSession);
    const [isScheduling, setIsScheduling] = useState(false);
    const [selectedSession, setSelectedSession] = useState<any | null>(null);
    const [isRecapOpen, setIsRecapOpen] = useState(false);

    // Reset form and close modal cleanly
    const closeModal = () => {
        setIsModalOpen(false);
        setNewSession(defaultSession);
    };

    const handleExportSessions = () => {
        if (sessions.length === 0) {
            toast("No records to export", "info");
            return;
        }

        const exportData = sessions.map(s => ({
            "Session Title": s.title,
            "Date": new Date(s.scheduled_at).toLocaleDateString(),
            "Time": new Date(s.scheduled_at).toLocaleTimeString(),
            "Duration (Min)": s.duration_minutes,
            "Type": s.session_type,
            "Attendee ID": s.mentee_id || s.mentor_id,
            "Status": new Date(s.scheduled_at) < new Date() ? "Completed" : "Upcoming"
        }));

        downloadCSV(exportData, `Sessions_Log_${new Date().toLocaleDateString()}.csv`);
        toast("Exported successfully!", "success");
    };

    useEffect(() => {
        // EAGER FETCH: Start as soon as we have a user ID.
        // We don't wait for 'authLoading' or 'profile' to be fully resolved.
        if (!user?.id) return;
        
        // ≡ƒƒó REAL-TIME SUBSCRIPTION
        const channel = supabase
            .channel('sessions-realtime')
            .on(
                'postgres_changes',
                { event: '*', schema: 'public', table: 'sessions' },
                () => {
                    logger.debug("SessionsPage", "Sessions table changed, refreshing...");
                    setRefreshTrigger(prev => prev + 1);
                }
            )
            .subscribe();

        const fetchSessions = async () => {
            try {
                const hasCachedData = sessions.length > 0;
                if (!hasCachedData) setLoading(true);

                // OPTIMIZED RELATIONAL QUERY: Uses joins instead of manual multi-step lookups.
                // For mentees, we also fetch sessions where mentee_id IS NULL AND mentor_id is their assigned mentor.
                let query = supabase
                    .from('sessions')
                    .select('*, mentor:profiles!mentor_id(id, full_name), mentee:profiles!mentee_id(id, full_name)');

                if (profile?.role === 'mentee') {
                    // Fetch assigned mentor if not in globalData
                    let mentorId = globalData.myMentor?.id;
                    if (!mentorId) {
                        const { data: menteeRow } = await supabase
                            .from('mentees')
                            .select('assigned_mentor_id')
                            .eq('id', user.id)
                            .single();
                        mentorId = menteeRow?.assigned_mentor_id;
                    }

                    if (mentorId) {
                        // Mentee sees: sessions assigned to them OR group sessions from their mentor
                        query = query.or(`mentee_id.eq.${user.id},and(mentee_id.is.null,mentor_id.eq.${mentorId})`);
                    } else {
                        query = query.eq('mentee_id', user.id);
                    }
                } else {
                    // Mentor sees all sessions they created
                    query = query.eq('mentor_id', user.id);
                }

                const { data: sessionsData, error } = await query.order('scheduled_at', { ascending: true });

                if (error) throw error;

                const formatted = (sessionsData || []).map((s: any) => {
                    const isGroupSession = !s.mentee_id;
                    const otherProfile = s.mentor_id === user.id 
                        ? (isGroupSession ? { full_name: 'All Mentees' } : s.mentee) 
                        : s.mentor;
                    const dateObj = new Date(s.scheduled_at);

                    return {
                        id: s.id,
                        mentor_id: s.mentor_id,
                        mentee_id: s.mentee_id,
                        meeting_link: s.meeting_link,
                        scheduled_at: s.scheduled_at,
                        title: s.title || 'Mentoring Session',
                        otherName: otherProfile?.full_name || (isGroupSession ? 'All Mentees' : 'User'),
                        time: dateObj.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
                        dateStr: formatDate(s.scheduled_at),
                        dayNum: dateObj.getDate().toString(),
                        monthStr: dateObj.toLocaleDateString([], { month: 'short' }),
                        duration: `${s.duration_minutes} min`,
                        duration_minutes: s.duration_minutes || 0,
                        status: s.status,
                        type: isGroupSession ? 'Group' : (s.session_type === 'one-on-one' ? '1-on-1' : s.session_type === 'group' ? 'Group' : 'Workshop')
                    };
                });


                if (JSON.stringify(formatted) !== JSON.stringify(sessions)) {
                    setSessions(formatted);
                    updateGlobalData('sessions', formatted);
                }

                // Populate mentee dropdown for Mentor role
                if (profile?.role === 'mentor') {
                    if (globalData.myMentees?.length > 0) {
                        setMyMentees(globalData.myMentees);
                    } else {
                        setMenteesLoading(true);
                        // Fetch from the `mentees` table using assigned_mentor_id
                        const { data: menteeRows } = await supabase
                            .from('mentees')
                            .select('id')
                            .eq('assigned_mentor_id', user.id);

                        if (menteeRows && menteeRows.length > 0) {
                            const ids = menteeRows.map((m: any) => m.id);
                            const { data: menteeProfiles } = await supabase
                                .from('profiles')
                                .select('id, full_name, student_id')
                                .in('id', ids);

                            const formattedMentees = (menteeProfiles || []).map((p: any) => ({
                                id: p.id,
                                name: p.full_name || 'Mentee',
                                student_id: p.student_id || ''
                            }));
                            setMyMentees(formattedMentees);
                        }
                        setMenteesLoading(false);
                    }
                }
            } catch (err: any) {
                logger.error("SessionsPage", "Fetch failed", {
                    message: err?.message || err,
                    code: err?.code
                });
            } finally {
                setLoading(false);
            }
        };

        fetchSessions();

        return () => {
            supabase.removeChannel(channel);
        };
    }, [refreshTrigger, user?.id]);

    // Dynamic status determination: If a scheduled session is in the past (including duration), treat as completed in UI
    const now = new Date();
    const upcomingSessions = sessions.filter(s => {
        if (s.status === 'cancelled') return false;
        if (s.status !== 'scheduled') return false;
        const duration = s.duration_minutes || 60;
        const endTime = new Date(new Date(s.scheduled_at).getTime() + duration * 60000);
        return endTime > now;
    });

    const completedSessions = sessions.filter(s => {
        if (s.status === 'completed') return true;
        if (s.status === 'scheduled') {
            const duration = s.duration_minutes || 60;
            const endTime = new Date(new Date(s.scheduled_at).getTime() + duration * 60000);
            return endTime <= now;
        }
        return false;
    });

    const totalMinutes = sessions.reduce((acc, session) => acc + (session.duration_minutes || 0), 0);
    const totalHoursScheduled = Math.round(totalMinutes / 60);

    const handleCancelSession = async (sessionId: string) => {
        const ok = await confirm({
            title: "Cancel Session",
            message: "Are you sure you want to cancel this session? This will remove it from the schedule.",
            confirmText: "Cancel Session",
            variant: "danger"
        });
        if (!ok) return;

        try {
            const { error } = await supabase.from('sessions').update({ status: 'cancelled' }).eq('id', sessionId);
            if (error) throw error;
            toast("Session cancelled.", "info");
            setRefreshTrigger(prev => prev + 1);
        } catch (error: any) {
            logger.error("SessionsPage", "Error cancelling session", error);

            toast("Failed to cancel session.", "error");
        }
    };

    const handleScheduleSession = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!user || profile?.role !== 'mentor') return;
        if (!newSession.mentee_id) {
            toast("Please select a mentee.", "warning");
            return;
        }
        if (!newSession.scheduled_at) {
            toast("Please pick a date and time.", "warning");
            return;
        }

        setIsScheduling(true);
        try {
            const meetingLink = (newSession.meeting_link || '').trim();
            // Auto-prefix https:// if user typed a URL without protocol
            const normalizedLink = meetingLink && !meetingLink.startsWith('http')
                ? `https://${meetingLink}`
                : meetingLink;

            const isGroupSession = newSession.mentee_id === "all";
            
            const { error } = await supabase
                .from('sessions')
                .insert({
                    mentor_id: user.id,
                    mentee_id: isGroupSession ? null : newSession.mentee_id,
                    title: newSession.title.trim() || 'Mentoring Session',
                    scheduled_at: new Date(newSession.scheduled_at).toISOString(),
                    duration_minutes: newSession.duration_minutes,
                    session_type: isGroupSession ? 'group' : newSession.session_type,
                    meeting_link: normalizedLink || null,
                    status: 'scheduled'
                });

            if (error) throw error;

            // 2. Notify mentee: Handled by 'on_session_created' trigger in Supabase.


            closeModal();
            toast("Session scheduled successfully!", "success");
            setRefreshTrigger(prev => prev + 1);

        } catch (error: any) {
            logger.error("SessionsPage", "Error scheduling session", {
                message: error.message,
                details: error.details,
                hint: error.hint,
                code: error.code
            });
            toast(error.message || "Failed to schedule session", "error");
        } finally {
            setIsScheduling(false);
        }
    };

    const hasVisibleContent = sessions.length > 0;
    // ZERO-LATENCY UI: Only block the whole page if we have NO identity info.
    const isBlocking = authLoading && !profile?.role && !user?.user_metadata?.role;

    if (isBlocking) {
        return (
            <div className="space-y-8 animate-in fade-in duration-500 pb-12">
                {/* Page title skeleton */}
                <div className="flex flex-col sm:flex-row sm:items-end justify-between gap-4">
                    <div className="space-y-3">
                        <div className="h-9 w-56 rounded-2xl bg-slate-200 dark:bg-slate-700 shimmer-skeleton" />
                        <div className="h-4 w-72 rounded-xl bg-slate-100 dark:bg-slate-800 shimmer-skeleton" />
                    </div>
                    <div className="h-12 w-40 rounded-2xl bg-slate-100 dark:bg-slate-800 shimmer-skeleton hidden sm:block" />
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                    {/* Session cards */}
                    <div className="lg:col-span-2 space-y-4">
                        <div className="h-5 w-44 rounded-lg bg-slate-200 dark:bg-slate-700 shimmer-skeleton" />
                        {[1, 2, 3].map(i => (
                            <div key={i} className="p-5 sm:p-6 rounded-2xl bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 flex items-center gap-5">
                                <div className="w-14 h-14 rounded-2xl bg-slate-200 dark:bg-slate-700 shrink-0 shimmer-skeleton" />
                                <div className="flex-1 space-y-2.5">
                                    <div className="h-4 w-1/2 rounded-lg bg-slate-200 dark:bg-slate-700 shimmer-skeleton" />
                                    <div className="h-3 w-1/3 rounded bg-slate-100 dark:bg-slate-800 shimmer-skeleton" />
                                    <div className="h-3 w-1/4 rounded bg-slate-100 dark:bg-slate-800 shimmer-skeleton" />
                                </div>
                                <div className="h-9 w-20 rounded-xl bg-slate-100 dark:bg-slate-800 shimmer-skeleton shrink-0" />
                            </div>
                        ))}
                    </div>
                    {/* Sidebar cards */}
                    <div className="space-y-4">
                        <div className="h-5 w-32 rounded-lg bg-slate-200 dark:bg-slate-700 shimmer-skeleton" />
                        <div className="p-5 rounded-2xl bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 space-y-4">
                            {[1, 2, 3].map(i => (
                                <div key={i} className="flex items-center gap-3">
                                    <div className="w-10 h-10 rounded-xl bg-slate-200 dark:bg-slate-700 shrink-0 shimmer-skeleton" />
                                    <div className="flex-1 space-y-2">
                                        <div className="h-3 w-1/2 rounded bg-slate-200 dark:bg-slate-700 shimmer-skeleton" />
                                        <div className="h-3 w-1/3 rounded bg-slate-100 dark:bg-slate-800 shimmer-skeleton" />
                                    </div>
                                </div>
                            ))}
                        </div>
                        <div className="h-32 rounded-2xl bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 shimmer-skeleton" />
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className="space-y-8 animate-in fade-in duration-500 pb-12">
            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-6">
                <div>
                    <h1 className="text-2xl sm:text-3xl font-bold text-slate-900 dark:text-white tracking-tight">
                        {profile?.role === 'mentor' ? 'Session Management' : 'My Sessions'}
                    </h1>
                    <p className="text-sm sm:text-base text-slate-500 dark:text-slate-400 mt-1">
                        {profile?.role === 'mentor' ? 'Schedule and manage mentor meetings.' : 'View and join your upcoming sessions.'}
                    </p>
                </div>
                {profile?.role === 'mentor' && (
                    <div className="flex flex-col sm:flex-row items-center gap-3 w-full sm:w-auto">
                        <button
                            onClick={handleExportSessions}
                            className="w-full sm:w-auto flex items-center justify-center gap-2 px-6 py-4 bg-white dark:bg-slate-900/60 text-slate-600 dark:text-slate-300 font-bold rounded-2xl border border-slate-200/50 dark:border-white/5 hover:bg-slate-50 dark:hover:bg-white/10 transition-all shadow-sm group active:scale-95"
                        >
                            <Video className="w-5 h-5 text-primary group-hover:scale-110 transition-transform" />
                            <span>Export Logs</span>
                        </button>
                        <button
                            onClick={() => setIsModalOpen(true)}
                            className="w-full sm:w-auto flex items-center justify-center gap-2 px-8 py-4 bg-primary text-white font-bold rounded-2xl shadow-xl shadow-primary/20 hover:bg-blue-600 hover:shadow-primary/40 transition-all active:scale-95">
                            <Plus className="w-5 h-5" /> Schedule Session
                        </button>
                    </div>
                )}
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                {/* Main List */}
                <div className="lg:col-span-2 space-y-6">
                    <h2 className="text-xl font-bold text-slate-800 dark:text-slate-200 flex items-center gap-2">
                        <CalendarIcon className="w-5 h-5 text-primary" /> Upcoming Schedule
                    </h2>

                    <div className="space-y-4">
                        {upcomingSessions.length === 0 ? (
                            <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} className="p-8 sm:p-12 text-center glass rounded-2xl border border-white/40 dark:border-slate-800/50 relative overflow-hidden group">
                                <div className="absolute inset-0 bg-gradient-to-br from-primary/5 to-transparent opacity-0 group-hover:opacity-100 transition-opacity" />
                                <div className="relative">
                                    <div className="w-16 h-16 sm:w-24 sm:h-24 rounded-2xl bg-gradient-to-br from-slate-50 to-slate-100 dark:from-slate-800 dark:to-slate-900 flex items-center justify-center shadow-max border border-white dark:border-slate-700/50 transition-transform duration-500">
                                        <Video className="w-8 h-8 sm:w-10 sm:h-10 text-primary drop-shadow-sm" />
                                    </div>
                                    <div className="absolute -bottom-2 -right-2 w-8 h-8 sm:w-10 sm:h-10 rounded-xl sm:rounded-2xl bg-white dark:bg-slate-800 flex items-center justify-center shadow-lg border border-slate-100 dark:border-slate-700 animate-bounce">
                                        <CalendarIcon className="w-4 h-4 sm:w-5 sm:h-5 text-blue-500" />
                                    </div>
                                </div>
                                <div className="mt-6 space-y-2 relative">
                                    <h3 className="text-xl sm:text-2xl font-black text-slate-900 dark:text-white tracking-tight">No upcoming sessions</h3>
                                    <p className="max-w-xs mx-auto text-xs sm:text-sm text-slate-500 dark:text-slate-400 font-medium">
                                        {profile?.role === 'mentor'
                                            ? "Your schedule is currently clear. Start by setting up a meeting with your mentees."
                                            : "Your mentor hasn't scheduled a session yet. Stay tuned or reach out to them directly."}
                                    </p>
                                </div>
                                {profile?.role === 'mentee' && (
                                    <div className="pt-6 relative">
                                        <a href="/dashboard/messages" className="inline-flex items-center gap-2 px-8 py-4 bg-primary text-white font-bold rounded-2xl shadow-xl shadow-primary/20 hover:bg-blue-600 transition-all text-sm active:scale-95">
                                            Message Your Mentor <ChevronRight className="w-4 h-4" />
                                        </a>
                                    </div>
                                )}
                            </motion.div>
                        ) : (
                            <div className="space-y-8">
                                {Object.entries(groupItemsByDate(upcomingSessions, s => s.scheduled_at)).map(([date, items]) => (
                                    <div key={date} className="space-y-4">
                                        <div className="flex items-center gap-4">
                                            <div className="h-[1px] flex-1 bg-gradient-to-r from-transparent via-slate-200 dark:via-slate-800 to-transparent" />
                                            <span className="text-[11px] font-black uppercase tracking-[0.2em] text-slate-400 bg-white/50 dark:bg-slate-900/50 px-3 py-1 rounded-full backdrop-blur-md border border-slate-200/50 dark:border-white/5 shadow-sm">{date}</span>
                                            <div className="h-[1px] flex-1 bg-gradient-to-r from-transparent via-slate-200 dark:via-slate-800 to-transparent" />
                                        </div>
                                        <div className="grid grid-cols-1 gap-4">
                                            {items.map((session: any, i: number) => (
                                                <motion.div
                                                    key={session.id}
                                                    initial={{ opacity: 0, y: 10 }}
                                                    animate={{ opacity: 1, y: 0 }}
                                                    transition={{ delay: i * 0.05 }}
                                                    className="p-4 sm:p-5 rounded-2xl bg-white/60 dark:bg-slate-900/40 backdrop-blur-xl border border-white/40 dark:border-slate-800/50 shadow-sm hover:shadow-md transition-all group overflow-hidden relative"
                                                >
                                                    <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 relative z-10">
                                                        <div className="flex items-start gap-5">
                                                            <div className="w-12 h-12 rounded-xl bg-primary/10 flex items-center justify-center text-primary shrink-0 shadow-inner group-hover:scale-105 transition-transform">
                                                                <Video className="w-5 h-5" />
                                                            </div>
                                                            <div className="min-w-0 text-left">
                                                                <div className="flex items-center gap-2 mb-1.5">
                                                                    <h3 className="font-bold text-lg text-slate-900 dark:text-white leading-tight truncate">{session.title}</h3>
                                                                    <span className="px-2 py-0.5 rounded-lg bg-primary/5 text-primary text-[10px] font-black uppercase tracking-widest border border-primary/10">{session.type}</span>
                                                                </div>
                                                                <div className="flex flex-wrap items-center gap-x-4 gap-y-2 text-sm text-slate-500 font-medium">
                                                                    <div className="flex items-center gap-1.5 bg-slate-100/50 dark:bg-slate-800/50 px-2 py-1 rounded-lg">
                                                                        <Clock className="w-4 h-4 text-slate-400" />
                                                                        <span>{session.time} ({session.duration})</span>
                                                                    </div>
                                                                    <div className="flex items-center gap-1.5">
                                                                        <div className="w-6 h-6 rounded-full bg-slate-200 dark:bg-slate-800 flex items-center justify-center">
                                                                            <User className="w-3.5 h-3.5 text-slate-500" />
                                                                        </div>
                                                                        <span className="truncate">with <span className="text-slate-900 dark:text-slate-200 font-bold">{session.otherName}</span></span>
                                                                    </div>
                                                                </div>
                                                            </div>
                                                        </div>

                                                        <div className="flex items-center gap-3 pt-4 md:pt-0 border-t md:border-0 border-slate-100 dark:border-slate-800">
                                                            {profile?.role === 'mentor' && (
                                                                <button
                                                                    onClick={() => handleCancelSession(session.id)}
                                                                    className="p-3 text-slate-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/10 rounded-xl transition-all active:scale-90"
                                                                    title="Cancel Session"
                                                                >
                                                                    <X className="w-5 h-5" />
                                                                </button>
                                                            )}
                                                            {session.meeting_link ? (
                                                                <a
                                                                    href={session.meeting_link}
                                                                    target="_blank"
                                                                    rel="noopener noreferrer"
                                                                    className="flex-1 md:flex-none flex items-center justify-center gap-2 px-6 py-3 bg-primary text-white font-bold rounded-xl shadow-lg shadow-primary/20 hover:shadow-primary/40 hover:-translate-y-0.5 transition-all text-sm active:scale-95"
                                                                >
                                                                    <Video className="w-4 h-4" /> Join Now
                                                                </a>
                                                            ) : (
                                                                <button className="flex-1 md:flex-none flex items-center justify-center gap-2 px-6 py-3 bg-slate-100 dark:bg-slate-800 text-slate-400 font-bold rounded-xl text-sm cursor-not-allowed italic">
                                                                    Link Pending
                                                                </button>
                                                            )}
                                                        </div>
                                                    </div>
                                                </motion.div>
                                            ))}
                                        </div>
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>

                    {completedSessions.length > 0 && (
                        <div className="pt-4 space-y-6">
                            <h2 className="text-xl font-bold text-slate-800 dark:text-slate-200 flex items-center gap-2">
                                <CheckCircle2 className="w-5 h-5 text-green-500" /> Recent History
                            </h2>
                            <div className="space-y-8">
                                {Object.entries(groupItemsByDate(completedSessions, s => s.scheduled_at)).map(([date, items]) => (
                                    <div key={date} className="space-y-4">
                                        <div className="flex items-center gap-3 pl-2">
                                            <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">{date}</span>
                                            <div className="h-[1px] flex-1 bg-slate-100 dark:bg-slate-800" />
                                        </div>
                                        <div className="bg-white/60 dark:bg-slate-900/40 backdrop-blur-xl rounded-2xl border border-white/40 dark:border-slate-800/50 overflow-hidden shadow-sm">
                                            {items.map((session: any) => (
                                                <div key={session.id} className="p-5 flex items-center justify-between hover:bg-white/80 dark:hover:bg-slate-800/60 transition-colors border-b border-slate-200/50 dark:border-slate-700/50 last:border-0 group cursor-pointer">
                                                    <div className="flex items-center gap-5 text-left">
                                                        <div className="w-10 h-10 rounded-xl bg-emerald-500/10 dark:bg-emerald-500/20 flex items-center justify-center text-emerald-600 dark:text-emerald-400 shadow-inner group-hover:scale-110 transition-transform">
                                                            <CheckCircle2 className="w-4 h-4" />
                                                        </div>
                                                        <div>
                                                            <p className="font-bold text-slate-900 dark:text-white text-sm">{session.title}</p>
                                                            <p className="text-xs text-slate-500">{session.time} ΓÇó with {session.otherName}</p>
                                                        </div>
                                                    </div>
                                                    <button
                                                        onClick={() => {
                                                            setSelectedSession(session);
                                                            setIsRecapOpen(true);
                                                        }}
                                                        className="p-2 hover:bg-slate-200 dark:hover:bg-slate-700 rounded-lg transition-colors"
                                                    >
                                                        <ChevronRight className="w-5 h-5 text-slate-400" />
                                                    </button>
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    )}
                </div>


                {/* Sidebar Mini-Calendar or Stats */}
                <div className="space-y-6">
                    <div className="p-5 rounded-2xl bg-white/60 dark:bg-slate-900/40 backdrop-blur-xl border border-slate-200/50 dark:border-slate-700/50 shadow-sm hover:shadow-md transition-shadow duration-300 relative overflow-hidden">

                        <h3 className="text-xl font-bold text-slate-900 dark:text-white mb-8 relative z-10 tracking-tight">Weekly Highlights</h3>
                        <div className="space-y-6 relative z-10">
                            <div className="flex items-center gap-5 group cursor-default">
                                <div className="w-12 h-12 rounded-xl bg-primary/10 flex items-center justify-center text-primary group-hover:scale-105 transition-transform">
                                    <Video className="w-5 h-5" />
                                </div>
                                <div>
                                    <p className="text-2xl font-black text-slate-900 dark:text-white">{totalHoursScheduled}</p>
                                    <p className="text-xs font-bold text-slate-500 uppercase tracking-wider">
                                        {profile?.role === 'mentor' ? 'Hours Scheduled' : 'Hours Logged'}
                                    </p>
                                </div>
                            </div>
                            <div className="flex items-center gap-4">
                                <div className="w-12 h-12 rounded-2xl bg-green-500/10 flex items-center justify-center text-green-500">
                                    <CheckCircle2 className="w-6 h-6" />
                                </div>
                                <div>
                                    <p className="text-2xl font-black text-slate-900 dark:text-white">{completedSessions.length}</p>
                                    <p className="text-xs font-bold text-slate-500 uppercase tracking-wider">Completed Sessions</p>
                                </div>
                            </div>
                            <div className="flex items-center gap-4">
                                <div className="w-12 h-12 rounded-2xl bg-amber-500/10 flex items-center justify-center text-amber-500">
                                    <AlertCircle className="w-6 h-6" />
                                </div>
                                <div>
                                    <p className="text-2xl font-black text-slate-900 dark:text-white">{upcomingSessions.length}</p>
                                    <p className="text-xs font-bold text-slate-500 uppercase tracking-wider">Upcoming Confirmed</p>
                                </div>
                            </div>
                        </div>
                    </div>

                    <div className="p-5 rounded-2xl bg-gradient-to-br from-slate-900 to-slate-800 text-white relative overflow-hidden shadow-xl border border-slate-700/50 group hover:shadow-2xl hover:shadow-primary/20 transition-all duration-300">
                        <h4 className="font-bold mb-2 relative z-10 text-lg">Quick Tip</h4>
                        <p className="text-sm text-slate-400 relative z-10 leading-relaxed">
                            Confirm your sessions at least 24 hours in advance to maintain a high professional rating.
                        </p>
                    </div>
                    <div className="p-5 rounded-2xl bg-gradient-to-br from-slate-900 to-slate-800 text-white relative overflow-hidden shadow-xl border border-slate-700/50 group hover:shadow-2xl hover:shadow-primary/20 transition-all duration-300">
                        <h4 className="font-bold mb-2 relative z-10 text-lg">Group Tip</h4>
                        <p className="text-sm text-slate-400 relative z-10 leading-relaxed">
                            Use Group Sessions to address common questions and build community among your mentees.
                        </p>
                    </div>
                </div>
            </div>

            {/* Schedule Session Modal */}
            {isModalOpen && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/50 backdrop-blur-sm">
                    <motion.div
                        initial={{ opacity: 0, scale: 0.95 }}
                        animate={{ opacity: 1, scale: 1 }}
                        className="bg-white dark:bg-slate-900 rounded-2xl w-full max-w-lg shadow-2xl overflow-hidden max-h-[90dvh] overflow-y-auto"
                    >
                        <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between">
                            <h2 className="text-xl font-bold text-slate-900 dark:text-white">Schedule New Session</h2>
                            <button onClick={closeModal} className="p-2 text-slate-400 hover:text-slate-600 dark:hover:text-slate-300 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors">
                                <X className="w-5 h-5" />
                            </button>
                        </div>

                        <form onSubmit={handleScheduleSession} className="p-6 space-y-4">
                            <div>
                                <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-1.5 ml-1">Session Title</label>
                                <input
                                    type="text"
                                    required
                                    value={newSession.title}
                                    onChange={(e) => setNewSession({ ...newSession, title: e.target.value })}
                                    className="w-full px-4 py-3 rounded-xl bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 outline-none focus:border-primary transition-all text-sm"
                                    placeholder="e.g., Mock Interview Preparation"
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-1.5 ml-1">Mentee</label>
                                {menteesLoading ? (
                                    <div className="w-full px-4 py-3.5 rounded-2xl bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 text-sm text-slate-400 flex items-center gap-2">
                                        <div className="w-4 h-4 border-2 border-primary border-t-transparent rounded-full animate-spin" />
                                        Loading your mentees...
                                    </div>
                                ) : (
                                    <div className="relative group/select">
                                        <select
                                            required
                                            value={newSession.mentee_id}
                                            onChange={(e) => {
                                                const val = e.target.value;
                                                setNewSession({ 
                                                    ...newSession, 
                                                    mentee_id: val,
                                                    session_type: val === 'all' ? 'group' : newSession.session_type
                                                });
                                            }}
                                            className="w-full pl-4 pr-10 py-3.5 rounded-2xl bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 outline-none focus:border-primary focus:ring-4 focus:ring-primary/5 transition-all text-sm appearance-none font-medium text-slate-900 dark:text-white"
                                        >
                                            <option value="" disabled>ΓÇö Select a Mentee ΓÇö</option>
                                            <optgroup label="Group Actions">
                                                <option value="all" className="font-bold text-primary">≡ƒæÑ All Mentees (Group Session)</option>
                                            </optgroup>
                                            <optgroup label="Individual Mentees">
                                                {myMentees.map(m => (
                                                    <option key={m.id} value={m.id}>{m.name} {m.student_id ? `(${m.student_id})` : ''}</option>
                                                ))}
                                            </optgroup>
                                            {myMentees.length === 0 && (
                                                <option value="" disabled>No mentees assigned yet</option>
                                            )}
                                        </select>
                                        <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400 group-hover/select:text-primary transition-colors">
                                            <User className="w-4 h-4" />
                                        </div>
                                    </div>
                                )}
                            </div>

                            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-1.5 ml-1 flex items-center gap-2">
                                        <CalendarIcon className="w-4 h-4 text-primary" /> Date & Time
                                    </label>
                                    <input
                                        type="datetime-local"
                                        required
                                        min={new Date(Date.now() - new Date().getTimezoneOffset() * 60000 + 3600000).toISOString().slice(0, 16)}
                                        value={newSession.scheduled_at}
                                        onChange={(e) => setNewSession({ ...newSession, scheduled_at: e.target.value })}
                                        className="w-full px-4 py-3.5 rounded-2xl bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 outline-none focus:border-primary focus:ring-4 focus:ring-primary/5 transition-all text-sm font-medium text-slate-900 dark:text-white"
                                    />
                                </div>
                                <div>
                                    <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-1.5 ml-1 flex items-center gap-2">
                                        <Clock className="w-4 h-4 text-primary" /> Duration
                                    </label>
                                    <select
                                        required
                                        value={newSession.duration_minutes}
                                        onChange={(e) => setNewSession({ ...newSession, duration_minutes: Number(e.target.value) })}
                                        className="w-full px-4 py-3.5 rounded-2xl bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 outline-none focus:border-primary focus:ring-4 focus:ring-primary/5 transition-all text-sm appearance-none font-medium text-slate-900 dark:text-white"
                                    >
                                        <option value="15">15 Minutes</option>
                                        <option value="30">30 Minutes</option>
                                        <option value="45">45 Minutes</option>
                                        <option value="60">60 Minutes</option>
                                        <option value="90">90 Minutes</option>
                                    </select>
                                </div>
                            </div>

                            <div>
                                <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-1.5 ml-1">Session Type</label>
                                <select
                                    required
                                    disabled={newSession.mentee_id === 'all'}
                                    value={newSession.session_type}
                                    onChange={(e) => setNewSession({ ...newSession, session_type: e.target.value })}
                                    className="w-full px-4 py-3.5 rounded-2xl bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 outline-none focus:border-primary focus:ring-4 focus:ring-primary/5 transition-all text-sm appearance-none font-medium text-slate-900 dark:text-white disabled:opacity-60"
                                >
                                    <option value="one-on-one">1-on-1 Mentoring</option>
                                    <option value="group">Group Session</option>
                                    <option value="workshop">Workshop</option>
                                </select>
                                {newSession.mentee_id === 'all' && (
                                    <p className="text-[10px] text-primary mt-1 ml-1 font-bold">Γ£¿ Automatically set to Group Session for multiple mentees</p>
                                )}
                            </div>

                            <div>
                                <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-1.5 ml-1">
                                    Meeting Link <span className="text-slate-400 font-normal">(Optional)</span>
                                </label>
                                <input
                                    type="text"
                                    value={newSession.meeting_link}
                                    onChange={(e) => setNewSession({ ...newSession, meeting_link: e.target.value })}
                                    className="w-full px-4 py-3 rounded-xl bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 outline-none focus:border-primary transition-all text-sm"
                                    placeholder="https://meet.google.com/..."
                                />
                                <p className="text-[10px] text-slate-400 mt-1 ml-1">Paste any meeting link (Google Meet, Zoom, Teams, etc.)</p>
                            </div>

                            <div className="pt-4 flex gap-3">
                                <button type="button" onClick={closeModal} className="flex-1 px-4 py-3 rounded-xl border border-slate-200 dark:border-slate-800 text-slate-600 dark:text-slate-400 font-bold hover:bg-slate-50 dark:hover:bg-slate-800 active:scale-95 transition-all">
                                    Cancel
                                </button>
                                <button
                                    type="submit"
                                    disabled={isScheduling || !newSession.mentee_id || !newSession.scheduled_at || !newSession.title.trim()}
                                    className="flex-1 px-4 py-3 rounded-xl bg-primary text-white font-bold hover:bg-blue-700 active:scale-95 shadow-lg shadow-primary/20 transition-all disabled:opacity-50 disabled:cursor-not-allowed"
                                >
                                    {isScheduling ? (
                                        <span className="flex items-center justify-center gap-2">
                                            <span className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin" />
                                            Scheduling...
                                        </span>
                                    ) : "Schedule Session"}
                                </button>
                            </div>
                        </form>
                    </motion.div>
                </div>
            )}

            {/* Session Recap Modal */}
            {isRecapOpen && selectedSession && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/50 backdrop-blur-sm">
                    <motion.div
                        initial={{ opacity: 0, scale: 0.95 }}
