                            <div className="w-20 h-20 sm:w-24 sm:h-24 rounded-2xl bg-primary/10 flex items-center justify-center text-primary border-2 border-primary/20 p-1">
                                <div className="w-full h-full rounded-xl sm:rounded-2xl bg-gradient-to-br from-primary/20 to-primary/5 flex items-center justify-center shadow-inner">
                                    <span className="text-xl sm:text-2xl font-black text-primary">
                                        {displayName.split(' ').map((n: string) => n[0]).join('').slice(0, 2).toUpperCase()}
                                    </span>
                                </div>
                            </div>
                        </div>
                        <div className="text-center sm:text-left min-w-0">
                            <h2 className="text-xl sm:text-2xl font-black text-slate-900 dark:text-white truncate">{fullName || displayName}</h2>
                            <p className="text-sm border-b border-transparent font-semibold capitalize text-slate-500 flex flex-wrap items-center justify-center sm:justify-start gap-1">
                                {!profile ? 'Synchronizing Profile...' : profile?.role === 'mentee' ? 'Mentee' : profile?.role === 'mentor' ? 'Faculty Mentor' : 'External Member'} 
                                <span className="opacity-30 mx-1">ΓÇó</span> 
                                <span className="truncate">{CONFIG.university.name}</span>
                            </p>
                            <div className="mt-4 flex flex-wrap items-center gap-2 justify-center sm:justify-start">
                                <span className="bg-emerald-500/10 text-emerald-600 dark:text-emerald-400 text-[9px] font-black px-2.5 py-1 rounded-full uppercase tracking-widest border border-emerald-500/20">Verified Profile</span>
                                {profile?.role === 'mentor' && (
                                    <span className="bg-primary/10 text-primary text-[9px] font-black px-2.5 py-1 rounded-full uppercase tracking-widest border border-primary/20">Faculty Member</span>
                                )}
                                {profile?.role === 'mentee' && (
                                    <span className="bg-blue-500/10 text-blue-600 dark:text-blue-400 text-[9px] font-black px-2.5 py-1 rounded-full uppercase tracking-widest border border-blue-500/20">Active Mentee</span>
                                )}
                            </div>
                        </div>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                        <div className="space-y-2">
                            <label className="text-sm font-bold text-slate-700 dark:text-slate-300 ml-1">Full Name</label>
