"use client";

import React, { ReactNode, ReactElement } from "react";
import { AlertTriangle, RefreshCw, Home } from "lucide-react";
import Link from "next/link";

interface ErrorBoundaryProps {
    children: ReactNode;
    fallback?: ReactElement;
}

interface ErrorBoundaryState {
    hasError: boolean;
    error: Error | null;
    errorInfo: React.ErrorInfo | null;
}

/**
 * Error Boundary component for catching and handling React component errors
 * Prevents single component crashes from bringing down entire page
 * Addresses SRS Requirement NFR-10: Fault-tolerant frontend
 */
export class ErrorBoundary extends React.Component<ErrorBoundaryProps, ErrorBoundaryState> {
    constructor(props: ErrorBoundaryProps) {
        super(props);
        this.state = {
            hasError: false,
            error: null,
            errorInfo: null,
        };
    }

    static getDerivedStateFromError(error: Error) {
        return { hasError: true };
    }

    componentDidCatch(error: Error, errorInfo: React.ErrorInfo) {
        console.error("ErrorBoundary caught an error:", error, errorInfo);
        this.setState({
            error,
            errorInfo,
        });
    }

    handleReset = () => {
        this.setState({
            hasError: false,
            error: null,
            errorInfo: null,
        });
    };

    render() {
        if (this.state.hasError) {
            return (
                this.props.fallback || (
                    <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-slate-900 via-slate-950 to-slate-900 p-4">
                        <div className="max-w-md w-full space-y-6">
                            {/* Error Icon */}
                            <div className="flex justify-center">
                                <div className="p-4 rounded-2xl bg-red-500/10 border border-red-500/20">
                                    <AlertTriangle className="w-10 h-10 text-red-500" />
                                </div>
                            </div>

                            {/* Error Message */}
                            <div className="space-y-2 text-center">
                                <h1 className="text-2xl font-bold text-white">Oops! Something went wrong</h1>
                                <p className="text-slate-400 text-sm">
                                    We encountered an unexpected error. Don&apos;t worry, our team has been notified.
                                </p>
                            </div>

                            {/* Error Details (Dev Only) */}
                            {process.env.NODE_ENV === "development" && this.state.error && (
                                <div className="p-4 rounded-lg bg-slate-800/50 border border-slate-700/50 font-mono text-xs text-red-400 max-h-40 overflow-auto">
                                    <p className="font-bold mb-2">Error Details:</p>
                                    <p>{this.state.error.message}</p>
                                    {this.state.errorInfo && (
                                        <details className="mt-2 text-slate-300">
                                            <summary className="cursor-pointer hover:text-white">Stack Trace</summary>
                                            <pre className="mt-2 text-[10px] overflow-auto">
                                                {this.state.errorInfo.componentStack}
                                            </pre>
                                        </details>
                                    )}
                                </div>
                            )}

                            {/* Action Buttons */}
                            <div className="flex gap-3">
                                <button
                                    onClick={this.handleReset}
                                    className="flex-1 px-4 py-3 rounded-xl bg-primary text-white font-bold hover:bg-blue-600 transition-colors flex items-center justify-center gap-2"
                                >
                                    <RefreshCw className="w-4 h-4" />
                                    Try Again
                                </button>
                                <Link
                                    href="/dashboard"
                                    className="flex-1 px-4 py-3 rounded-xl bg-slate-800 text-slate-100 font-bold hover:bg-slate-700 transition-colors flex items-center justify-center gap-2"
                                >
                                    <Home className="w-4 h-4" />
                                    Go Home
                                </Link>
                            </div>

                            {/* Support Message */}
                            <p className="text-center text-xs text-slate-500">
                                If this problem persists, please contact{" "}
                                <a href="mailto:support@nexus-mentorship.com" className="text-primary hover:underline">
                                    support@nexus-mentorship.com
                                </a>
                            </p>
                        </div>
                    </div>
                )
            );
        }

        return this.props.children;
    }
}

"use client";

import { useEffect } from "react";
import { supabase } from "@/lib/supabase";
import { useAuth, AppNotification } from "@/contexts/AuthContext";
import { useToast } from "./Toast";
import { Bell, Calendar, CheckSquare, MessageSquare, UserPlus, Megaphone } from "lucide-react";
import React from "react";

export function NotificationSync() {
    const { user, addNotification } = useAuth();
    const { toast } = useToast();

    useEffect(() => {
        if (!user?.id) return;

        const notificationSubscription = supabase
            .channel(`public:notifications:recipient_id=eq.${user.id}`)
            .on(
                'postgres_changes',
                {
                    event: 'INSERT',
                    schema: 'public',
                    table: 'notifications',
                    filter: `recipient_id=eq.${user.id}`
                },
                (payload) => {
                    const newNotif = payload.new as AppNotification;

                    // Update global state
                    addNotification(newNotif);

                    // Trigger professional toast
                    toast(
                        `${newNotif.title}: ${newNotif.content}`,
                        newNotif.type === 'request' ? 'warning' : 'info'
                    );
                }
            )
            .subscribe();

        return () => {
            notificationSubscription.unsubscribe();
        };
    }, [user?.id, toast, addNotification]);

    return null;
}

"use client";

import React, { useEffect } from "react";
import { useRouter } from "next/navigation";
import { useAuth } from "@/contexts/AuthContext";
import { logger } from "@/lib/logger";

export function ProtectedRoute({ children }: { children: React.ReactNode }) {
    const router = useRouter();
    const { user, loading } = useAuth();
    const [hasLocalSession, setHasLocalSession] = React.useState<boolean | null>(null);
    const [mounted, setMounted] = React.useState(false);

    useEffect(() => {
        setMounted(true);
        // Fast-path: Check for a valid session token in localStorage immediately
        try {
            const keys = Object.keys(localStorage);
            const sessionKey = keys.find(k => k.startsWith('sb-') && k.endsWith('-auth-token'));
            if (sessionKey) {
                const stored = JSON.parse(localStorage.getItem(sessionKey) || '{}');
                const expiresAt = stored?.expires_at || 0;
                if (expiresAt * 1000 > Date.now()) {
                    setHasLocalSession(true);
                    return;
                }
            }
        } catch (e) {
            logger.warn("ProtectedRoute", "Error checking local session", e);
        }
        setHasLocalSession(false);
    }, []);

    useEffect(() => {
        // Only redirect if:
        // 1. Component is mounted (to avoid hydration mismatch)
        // 2. Local fast-path check says no session (hasLocalSession === false)
        // 3. Network check says no user (!loading && !user)
        if (mounted && hasLocalSession === false && !loading && !user) {
            // REDIRECTION SYNC: Use /login instead of / for better UX and consistency with middleware
            window.location.href = "/login";
        }
    }, [user, loading, hasLocalSession, mounted]);

    // If AuthContext already resolved (sync-init), show children immediately.
    // Otherwise, if we're truly loading and have no cached session, show the skeleton.
    // HYDRATION: Always show skeleton until mounted to match server structure.
    if (!mounted || (loading && !user && hasLocalSession !== true)) {
        return (
            <div className="flex-1 bg-slate-950 duration-700 min-h-screen" />
        );
    }

    return <>{children}</>;
}

